#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <string.h>
#include <signal.h>
#include <errno.h>
#include <unistd.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>

// Define the I2C address of the Si1133 sensor
#define SI1133_ADDR 0x60

// Define the register addresses for the Si1133 sensor
#define SI1133_REG_PART_ID 0x00
#define SI1133_REG_ALS_VIS_DATA0 0x22
#define SI1133_REG_ALS_IR_DATA0 0x24
#define SI1133_REG_UV_INDEX0 0x26
#define SI1133_REG_COMMAND 0x08
#define SI1133_REG_HW_KEY 0x07

// Define the command to start measurement
#define SI1133_CMD_START 0x01

// Global variables
int i2c_fd;
FILE *log_file;
volatile sig_atomic_t program_running = 1;

// Structure to hold sensor data
typedef struct {
    uint16_t uv_index;
    uint16_t als_vis;
    uint16_t als_ir;
} sensor_data_t;

// Function prototypes
int si1133_init();
int si1133_read_data(sensor_data_t *data);
int log_data(sensor_data_t data);
void signal_handler(int signal);
void cleanup();

// Signal handler function
void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully.\n", signal);
}

// Cleanup function to close I2C and file
void cleanup() {
    if (i2c_fd >= 0) {
        close(i2c_fd);
    }
    if (log_file!= NULL) {
        fclose(log_file);
    }
}

// Initialize the Si1133 sensor
int si1133_init() {
    // Write the HW key to unlock the sensor
    if (wiringPiI2CWriteReg8(i2c_fd, SI1133_REG_HW_KEY, 0x17) < 0) {
        fprintf(stderr, "Error writing to HW_KEY register: %s\n", strerror(errno));
        return -1;
    }
    delay(10); // Wait for the key to be applied

    // Initialize the sensor (example initialization sequence)
    if (wiringPiI2CWriteReg8(i2c_fd, SI1133_REG_COMMAND, 0x37) < 0) {
        fprintf(stderr, "Error writing to COMMAND register: %s\n", strerror(errno));
        return -1;
    }
    delay(10); // Wait for initialization to complete

    return 0;
}

// Read data from the Si1133 sensor
int si1133_read_data(sensor_data_t *data) {
    int als_vis_low, als_vis_high, als_ir_low, als_ir_high, uv_index_low, uv_index_high;

    // Read UV index data
    uv_index_low = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_UV_INDEX0);
    uv_index_high = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_UV_INDEX0 + 1);
    if (uv_index_low < 0 || uv_index_high < 0) {
        fprintf(stderr, "Error reading UV index data: %s\n", strerror(errno));
        return -1;
    }
    data->uv_index = (uint16_t)((uv_index_high << 8) | uv_index_low);

    // Read ALS visible data
    als_vis_low = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_ALS_VIS_DATA0);
    als_vis_high = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_ALS_VIS_DATA0 + 1);
    if (als_vis_low < 0 || als_vis_high < 0) {
        fprintf(stderr, "Error reading ALS visible data: %s\n", strerror(errno));
        return -1;
    }
    data->als_vis = (uint16_t)((als_vis_high << 8) | als_vis_low);

    // Read ALS IR data
    als_ir_low = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_ALS_IR_DATA0);
    als_ir_high = wiringPiI2CReadReg8(i2c_fd, SI1133_REG_ALS_IR_DATA0 + 1);
    if (als_ir_low < 0 || als_ir_high < 0) {
        fprintf(stderr, "Error reading ALS IR data: %s\n", strerror(errno));
        return -1;
    }
    data->als_ir = (uint16_t)((als_ir_high << 8) | als_ir_low);

    return 0;
}

// Log the data to a file
int log_data(sensor_data_t data) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s, UV Index: %d, Ambient Light (VIS): %d, Ambient Light (IR): %d\n",
            timestamp, data.uv_index, data.als_vis, data.als_ir);
    fflush(log_file); // Ensure data is written to disk immediately

    return 0;
}

int main() {
    sensor_data_t sensor_data;

    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize I2C
    i2c_fd = wiringPiI2CSetup(SI1133_ADDR);
    if (i2c_fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
        return 1;
    }

    // Initialize the sensor
    if (si1133_init() == -1) {
        fprintf(stderr, "Si1133 initialization failed.\n");
        cleanup();
        return 1;
    }

    // Open the log file
    log_file = fopen("light_data.log", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file: %s\n", strerror(errno));
        cleanup();
        return 1;
    }

    // Main loop
    while (program_running) {
        // Read data from the sensor
        if (si1133_read_data(&sensor_data) == 0) {
            // Log the data
            if (log_data(sensor_data)!= 0) {
                fprintf(stderr, "Failed to log data.\n");
            }
        } else {
            fprintf(stderr, "Failed to read data from sensor.\n");
        }

        // Wait for 1 second
        delay(1000);
    }

    // Cleanup and exit
    cleanup();
    return 0;
}

