  int pir_state;
  int buzz_state;

  gpioInitialise();

  gpioSetMode(PIR_PIN, PI_INPUT);
  gpioSetMode(BUZZER_PIN, PI_OUTPUT);

  pir_state = PIR_OFF;
  buzz_state = BUZZER_OFF;

  gpioSetAlertFunc(PIR_PIN, pir_interrupt_callback);

  while (1) {
