      pir_state = PIR_OFF;
    } else if (pir_state == PIR_OFF && buzz_state == BUZZER_ON) {
      gpioWrite(BUZZER_PIN, BUZZER_OFF);
      buzz_state = BUZZER_OFF;
      pir_state = PIR_OFF;
    }
  }

  gpioTerminate();

  return 0;
}

