#define SERVER_IP "127.0.0.1" // Localhost for testing
#define TEMPERATURE_THRESHOLD 30.0 // Temperature threshold in Celsius
#define MAX_RETRIES 3

// Global variables
FILE *logFile = NULL;
bool running = true;
int socket_desc;
struct sockaddr_in server_addr, client_addr;
socklen_t client_len = sizeof(client_addr);

// Function prototypes
float readTemperature();
int sendTemperature(float temperature);
int receiveFanSpeed(int *fanSpeed);
void setFanSpeed(int percentage);
void logData(time_t timestamp, float temperature, int fanSpeed);
void signalHandler(int signum);
int initializeServer();
int processClient(float temperature);

// Function to read temperature from MAX31855 via SPI
float readTemperature() {
    unsigned char data[MAX31855_DATA_SIZE];
    int retries = 0;

    while (retries < MAX_RETRIES) {
        if (wiringPiSPIDataRW(SPI_CHANNEL, data, MAX31855_DATA_SIZE) == -1) {
            fprintf(stderr, "SPI read failed (attempt %d): %s\n", retries + 1, strerror(errno));
            retries++;
            delay(10); // Short delay before retry
            continue;
        }

        // Check for errors in the status register (bit 0 of byte 3)
        if (data[3] & 0x07) {
            fprintf(stderr, "MAX31855 error: %s%s%s (attempt %d)\n",
                    (data[3] & 0x01) ? "Open circuit, " : "",
                    (data[3] & 0x02) ? "Short to GND, " : "",
                    (data[3] & 0x04) ? "Short to VCC, " : "",
                    retries + 1);
            retries++;
            delay(10); // Short delay before retry
            continue;
        }

        // Extract temperature data (bits 3-14 of byte 0 and byte 1)
        int16_t raw_temp = ((int16_t)data[0] << 6) | (data[1] >> 2);
        float temperature = (float)raw_temp / 64.0;
        return temperature;
    }

    fprintf(stderr, "MAX31855 read failed after %d retries. Returning -273.15\n", MAX_RETRIES);
    return -273.15; // Return absolute zero on failure
}

// Function to send temperature data via UDP
int sendTemperature(float temperature) {
    char message[50];
    snprintf(message, sizeof(message), "%.2f", temperature);

    if (sendto(socket_desc, message, strlen(message), 0, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        fprintf(stderr, "Send failed: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Function to receive fan speed from the server via UDP
int receiveFanSpeed(int *fanSpeed) {
    char buffer[50];
    ssize_t recv_len;

    recv_len = recvfrom(socket_desc, buffer, sizeof(buffer) - 1, 0, (struct sockaddr *)&server_addr, &client_len);
    if (recv_len < 0) {
        fprintf(stderr, "recvfrom failed: %s\n", strerror(errno));
        return -1;
    }

    buffer[recv_len] = '\0';
    *fanSpeed = atoi(buffer);
    return 0;
}

// Function to set fan speed using PWM
void setFanSpeed(int percentage) {
    if (percentage < 0) percentage = 0;
    if (percentage > 100) percentage = 100;

    int pwmValue = (int)((percentage / 100.0) * 1023.0);
    pwmWrite(FAN_PIN, pwmValue);
}

// Function to log data to file
void logData(time_t timestamp, float temperature, int fanSpeed) {
    struct tm *timeinfo;
    char timeString[80];

    timeinfo = localtime(&timestamp);
    strftime(timeString, sizeof(timeString), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(logFile, "%s,%.2f,%d\n", timeString, temperature, fanSpeed);
    fflush(logFile); // Ensure data is written to disk immediately
}

// Signal handler for graceful shutdown
void signalHandler(int signum) {
    if (signum == SIGINT) {
        printf("Caught SIGINT, exiting...\n");
        running = false;
        setFanSpeed(0); // Stop the fan
        if (logFile != NULL) {
            fclose(logFile);
        }
        close(socket_desc);
        wiringPiSetup(); // Reinitialize wiringPi to release GPIO pins properly.
        exit(0);
    }
}

// Function to initialize the UDP server
int initializeServer() {
    socket_desc = socket(AF_INET, SOCK_DGRAM, 0);
    if (socket_desc < 0) {
        fprintf(stderr, "Could not create socket: %s\n", strerror(errno));
        return -1;
    }

    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = inet_addr(SERVER_IP);
    server_addr.sin_port = htons(SERVER_PORT);

    // Bind to the specified port
    if (bind(socket_desc, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
        fprintf(stderr, "Bind failed: %s\n", strerror(errno));
        close(socket_desc);
        return -1;
    }

    printf("Server listening on port %d\n", SERVER_PORT);
    return 0;
}

// Function to process the client request and determine fan speed
