        fclose(log_file);
    }
    pinMode(FAN_PIN, INPUT); // Set GPIO back to input
    pwmWrite(FAN_PIN, 0);      // Turn off the fan
    exit(0);
}

// Initializes the wiringPi library and sets up the PWM pin.
int initialize_gpio(Config *config) {
    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return -1;
    }

    pinMode(config->fan_pin, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(PWM_RANGE);
    pwmSetClock(32); // Adjust PWM clock for desired PWM frequency (1 MHz / 32)

    return 0;
}

// Initializes the SPI interface.
int initialize_spi(Config *config) {
    if (wiringPiSPISetup(config->spi_channel, config->spi_speed) == -1) {
        fprintf(stderr, "Error initializing SPI: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Reads the temperature from the MAX31855 thermocouple amplifier.
double read_temperature(int channel) {
    unsigned char data[4];
    int32_t raw_temperature;
    double temperature;

    data[0] = 0x01; // Read command
    data[1] = 0x80; // Dummy byte
    data[2] = 0x00; // Dummy byte
    data[3] = 0x00; // Dummy byte

    wiringPiSPIDataRW(channel, data, 4);

    // Extract the temperature data (bits 31-18)
    raw_temperature = ((data[0] & 0x3F) << 18) | (data[1] << 6) | (data[2] >> 2);

    // Check for fault bits (bits 4 and 3 of data[3])
    if (data[3] & 0x04) {
        fprintf(stderr, "Thermocouple open circuit fault.\n");
        return -273.15; // Return absolute zero on fault
    } else if (data[3] & 0x02) {
        fprintf(stderr, "Thermocouple short to GND fault.\n");
        return -273.15; // Return absolute zero on fault
    } else if (data[3] & 0x01) {
        fprintf(stderr, "Thermocouple short to VCC fault.\n");
        return -273.15; // Return absolute zero on fault
    }

    // Convert the raw temperature to Celsius
    temperature = raw_temperature * 0.25;

    return temperature;
}

// Controls the fan speed based on the temperature.
int control_fan_speed(double temperature) {
    int fan_speed;

    if (temperature < TEMP_THRESHOLD) {
        fan_speed = 0;
    } else if (temperature > 80.0) {
        fan_speed = 100;
    } else {
        fan_speed = (int)(((temperature - TEMP_THRESHOLD) / (80.0 - TEMP_THRESHOLD)) * 100.0);
    }

    pwmWrite(FAN_PIN, fan_speed * PWM_RANGE / 100); // Set PWM duty cycle

    return fan_speed;
}

// Logs the temperature and fan speed to a file.
void log_data(double temperature, int fan_speed) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s, Temperature: %.2f C, Fan Speed: %d%%\n", timestamp, temperature, fan_speed);
    fflush(log_file); // Ensure data is written immediately
}

int main() {
    Config config = {SPI_CHANNEL, SPI_SPEED, FAN_PIN, TEMP_THRESHOLD, LOG_FILE};
    double temperature;
    int fan_speed;

    // Set up signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize GPIO
    if (initialize_gpio(&config) == -1) {
        return 1;
    }

    // Initialize SPI
    if (initialize_spi(&config) == -1) {
        return 1;
    }

    // Open the log file
    log_file = fopen(config.log_file, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return 1;
    }

