        // Read temperature
        temperature = read_temperature(config.spi_channel);

        if (temperature >= -273.0) {
            // Control fan speed
            fan_speed = control_fan_speed(temperature);

            // Log data
            log_data(temperature, fan_speed);

            printf("Temperature: %.2f C, Fan Speed: %d%%\n", temperature, fan_speed);
        } else {
            fprintf(stderr, "Error reading temperature. Skipping fan control and logging.\n");
        }

