    int bytes_read = recv(client_socket, buffer, buffer_size - 1, 0);
    if (bytes_read < 0) {
        perror("recv failed");
        return -1;
    } else if (bytes_read == 0) {
        printf("Client disconnected\n");
        close_client_socket(client_socket);
