// Constants
#define PIR_GPIO 4
#define BUZZER_GPIO 18
#define DEBOUNCE_INTERVAL 200 // milliseconds
#define BUZZER_DURATION 500   // milliseconds

// Global variables
static volatile uint32_t last_tick = 0;
static FILE *log_file = NULL;
static volatile int running = 1;

// Function prototypes
int init_gpio();
void motion_detected_callback(int gpio, int level, uint32_t tick);
void trigger_buzzer();
void log_motion_event();
void signal_handler(int signal);

// Structure to hold GPIO configuration
typedef struct {
    int pir_gpio;
    int buzzer_gpio;
    int debounce_interval;
    int buzzer_duration;
} gpio_config_t;

// Initialize GPIO pins and set up interrupt handler
int init_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(PIR_GPIO, PI_INPUT);
    gpioSetPullUpDown(PIR_GPIO, PI_PUD_DOWN); // Use pull-down resistor

    gpioSetMode(BUZZER_GPIO, PI_OUTPUT);
    gpioWrite(BUZZER_GPIO, 0); // Ensure buzzer is off initially

    gpioSetAlertFuncEx(PIR_GPIO, motion_detected_callback, NULL);

    return 0;
}

// Interrupt handler function
void motion_detected_callback(int gpio, int level, uint32_t tick) {
    uint32_t diff = tick - last_tick;

    if (diff > DEBOUNCE_INTERVAL * 1000) { // Convert milliseconds to microseconds
        trigger_buzzer();
        log_motion_event();
        last_tick = tick;
    }
}

// Activate and deactivate the piezo buzzer
void trigger_buzzer() {
    gpioWrite(BUZZER_GPIO, 1);
    gpioDelay(BUZZER_DURATION);
    gpioWrite(BUZZER_GPIO, 0);
}

// Log motion event with timestamp to file
void log_motion_event() {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (log_file != NULL) {
        fprintf(log_file, "%s - Motion Detected\n", timestamp);
        fflush(log_file); // Ensure immediate write to file
    } else {
        fprintf(stderr, "Error: Log file is not open.\n");
    }
}

// Signal handler for graceful termination
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully.\n", signal);
    running = 0;
    gpioWrite(BUZZER_GPIO, 0);
    gpioTerminate();
    if (log_file != NULL) {
        fclose(log_file);
    }
    exit(0);
}

int main() {
    // Open log file
    log_file = fopen("motion_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return 1;
    }

    // Initialize GPIO
    if (init_gpio() != 0) {
        fclose(log_file);
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Motion detection node started. Press Ctrl+C to exit.\n");

    while (running) {
        gpioDelay(100); // Reduce CPU usage
    }

    return 0;
}

