#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <unistd.h>
#include <signal.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <pigpio.h>

// Constants
#define IR_SENSOR_PIN 17
#define SERVO_PIN 18
#define SERVO_CLOSED_PW 1500
#define SERVO_OPEN_PW 2000
#define FEEDING_DURATION_SEC 5
#define DEBOUNCE_DELAY_MS 500
#define SERVER_IP "192.168.1.100"
#define SERVER_PORT 5000

// Global variables
int udp_socket; // UDP socket file descriptor
FILE *log_file; // File pointer for the log file
volatile sig_atomic_t program_running = 1; // Flag to control program execution

// Function prototypes
void signal_handler(int signal);
char* get_timestamp();
int log_event(const char* event_message);
int send_udp_message(const char* message);
int open_feeder();
int close_feeder();
int read_ir_sensor();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    if (signal == SIGINT) {
        program_running = 0; // Set the flag to exit the main loop
        printf("\nCaught signal, exiting gracefully...\n");
    }
}

// Function to get the current timestamp
char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    static char timestamp[20]; // Static buffer to store the timestamp
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp;
}

// Function to log an event to the file and console
int log_event(const char* event_message) {
    char* timestamp = get_timestamp();
    fprintf(log_file, "%s: %s\n", timestamp, event_message);
    fflush(log_file); // Ensure the log is written to disk immediately
    printf("%s: %s\n", timestamp, event_message);
    return 0;
}

// Function to send a UDP message
int send_udp_message(const char* message) {
    struct sockaddr_in server_addr;
    socklen_t server_addr_len = sizeof(server_addr);

    memset(&server_addr, 0, server_addr_len);
    server_addr.sin_family = AF_INET;
    server_addr.sin_port = htons(SERVER_PORT);
    if (inet_pton(AF_INET, SERVER_IP, &server_addr.sin_addr) <= 0) {
        log_event("Error: Invalid address/ Address not supported \n");
        perror("inet_pton");
        return -1;
    }

    if (sendto(udp_socket, message, strlen(message), 0, (struct sockaddr *)&server_addr, server_addr_len) < 0) {
        log_event("Error sending UDP message");
        perror("sendto");
        return -1;
    }
    return 0;
}

// Function to open the bird feeder
int open_feeder() {
    if (gpioPWM(SERVO_PIN, SERVO_OPEN_PW) != 0) {
        log_event("Error opening feeder");
        return -1;
    }
    return 0;
}

// Function to close the bird feeder
int close_feeder() {
    if (gpioPWM(SERVO_PIN, SERVO_CLOSED_PW) != 0) {
        log_event("Error closing feeder");
        return -1;
    }
    return 0;
}

// Function to read the IR sensor value with retry logic
int read_ir_sensor() {
    int sensor_value = gpioRead(IR_SENSOR_PIN);
    if (sensor_value < 0) {
        log_event("Error reading IR sensor, retrying...");
        usleep(100000); // 100ms
        sensor_value = gpioRead(IR_SENSOR_PIN);
        if (sensor_value < 0) {
            log_event("Error reading IR sensor after retry");
            return -1; // Indicate error
        }
    }
    return sensor_value;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(IR_SENSOR_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Initialize servo to closed position
    close_feeder();

    // Open the log file
    log_file = fopen("feeding_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        gpioTerminate();
        return 1;
    }

    // Create UDP socket
    udp_socket = socket(AF_INET, SOCK_DGRAM, 0);
    if (udp_socket < 0) {
        perror("Error creating socket");
        log_event("Error creating socket");
        fclose(log_file);
        gpioTerminate();
        return 1;
    }

    // Register signal handler
    signal(SIGINT, signal_handler);

    // Debounce variable
    time_t last_trigger_time = 0;

    // Main loop
    while (program_running) {
        int sensor_value = read_ir_sensor();
        if (sensor_value == 0) { // Obstacle detected (low value)
            time_t current_time = time(NULL);
            if (difftime(current_time, last_trigger_time) >= (double)DEBOUNCE_DELAY_MS / 1000.0) {
                char* timestamp = get_timestamp();
                char log_message[100];
                snprintf(log_message, sizeof(log_message), "Feeder triggered");
                log_event(log_message);

                char udp_message[100];
                snprintf(udp_message, sizeof(udp_message), "%s,feeder_triggered", timestamp);
                send_udp_message(udp_message);

                open_feeder();
                sleep(FEEDING_DURATION_SEC);
                close_feeder();

                last_trigger_time = current_time; // Update last trigger time
                usleep(DEBOUNCE_DELAY_MS * 1000); // Debounce delay
            }
        }
        usleep(100000); // Check sensor every 100ms
    }

    // Cleanup
    close(udp_socket);
    close_feeder(); // Ensure the feeder is closed on exit
    fclose(log_file);
    gpioTerminate();

    return 0;
}

