#include <stdio.h>
#include <wiringPi.h>

#define SERVO 18
#define SENSOR 17

int main(void)
{
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Unable to setup wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Setup SERVO
    pinMode(SERVO, OUTPUT);
    digitalWrite(SERVO, LOW);
    delay(500);
    // Setup SENSOR
    pinMode(SENSOR, INPUT);
    // Setup feeding log file
    FILE* fp = fopen("feeding_log.txt", "w");
    if (fp == NULL) {
        fprintf(stderr, "Unable to open feeding_log.txt: %s\n", strerror(errno));
        return 1;
    }

    // Main loop
    while (1) {
        // Handle sensor read failures
        if (digitalRead(SENSOR) == -1) {
            fprintf(stderr, "Unable to read sensor: %s\n", strerror(errno));
            delay(500);
            continue;
        }
        // Handle servo control errors
        if (digitalWrite(SERVO, HIGH) == -1) {
            fprintf(stderr, "Unable to control servo: %s\n", strerror(errno));
            delay(500);
            continue;
        }
        // Handle feeding
        if (digitalRead(SENSOR) == HIGH) {
            digitalWrite(SERVO, LOW);
            fprintf(fp, "Feeding bird at %ld\n", time(NULL));
            delay(500);
        }
    }

    fclose(fp);

    return 0;
}

