    if (distance < MIN_DISTANCE || distance > MAX_DISTANCE) {
        fprintf(stderr, "Error: Distance reading out of range: %.2f cm.  Must be between %.2f and %.2f cm.\n",
                distance, MIN_DISTANCE, MAX_DISTANCE);
        return 0; // Indicate invalid
    }
    return 1; // Indicate valid
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    running = 0;
}

// MQTT connection callback function
void connect_callback(struct mosquitto *mosq, void *userdata, int result) {
    if (!result) {
        printf("MQTT connected to broker\n");
    } else {
        fprintf(stderr, "MQTT connection error: %s\n", mosquitto_connack_string(result));
    }
}

// MQTT message callback function
void message_callback(struct mosquitto *mosq, void *userdata, const struct mosquitto_message *message) {
    if (message->payloadlen) {
        printf("Received message on topic %s: %s\n", message->topic, (char *)message->payload);
        // Parse the message (e.g., set servo angle)
        char *token = strtok((char *)message->payload, ",");
        if (token!= NULL && strcmp(token, "set_servo_angle") == 0) {
            token = strtok(NULL, ",");
            if (token!= NULL) {
                int angle = atoi(token);
                set_servo_angle(angle);
            }
        }
    }
}

// Function to send distance reading to MQTT broker
void send_mqtt_message(float distance) {
    char buffer[100];
    snprintf(buffer, sizeof(buffer), "{\"distance\": %.2f}", distance);

    int ret = mosquitto_publish(mosq, NULL, MQTT_TOPIC, strlen(buffer), buffer, 0, false);
    if (ret!= MOSQ_ERR_SUCCESS) {
        fprintf(stderr, "Error publishing message: %s\n", mosquitto_strerror(ret));
    }
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(SERVO_PIN, PI_OUTPUT);

    // Initialize servo angle
    set_servo_angle(servo_angle);

    // Initialize MQTT
    mosquitto_lib_init();
    mosq = mosquitto_new(NULL, true, NULL);
    if (!mosq) {
        fprintf(stderr, "Error: Out of memory.\n");
        gpioTerminate();
        mosquitto_lib_cleanup();
        return 1;
    }

    mosquitto_connect_callback_set(mosq, connect_callback);
    mosquitto_message_callback_set(mosq, message_callback);

    int ret = mosquitto_connect(mosq, MQTT_BROKER_ADDRESS, MQTT_BROKER_PORT, 60);
    if (ret!= MOSQ_ERR_SUCCESS) {
        fprintf(stderr, "Error connecting to MQTT broker: %s\n", mosquitto_strerror(ret));
        mosquitto_destroy(mosq);
        mosquitto_lib_cleanup();
        gpioTerminate();
        return 1;
    }

    mosquitto_loop_start(mosq);

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (running) {
        // Sweep servo
        for (int angle = 0; angle <= 180; angle += 10) {
            set_servo_angle(angle);
            gpioDelay(500); // Wait for servo to reach the angle

            float distance = measure_distance();

            if (distance > 0) {
                if (validate_distance(distance)) {
                    printf("Distance: %.2f cm at angle %d degrees\n", distance, angle);
                    send_mqtt_message(distance);

                    if (distance < ALERT_DISTANCE) {
                        printf("Alert: Object detected within %.2f cm at angle %d degrees!\n", distance, angle);
                        // In a real implementation, you would trigger an alert here
                        // (e.g., blink LED or play a sound)
                    }
                }
            }
        }

        // Reverse sweep
        for (int angle = 180; angle >= 0; angle -= 10) {
            set_servo_angle(angle);
            gpioDelay(500); // Wait for servo to reach the angle

            float distance = measure_distance();

            if (distance > 0) {
                if (validate_distance(distance)) {
                    printf("Distance: %.2f cm at angle %d degrees\n", distance, angle);
                    send_mqtt_message(distance);

                    if (distance < ALERT_DISTANCE) {
                        printf("Alert: Object detected within %.2f cm at angle %d degrees!\n", distance, angle);
                        // In a real implementation, you would trigger an alert here
                        // (e.g., blink LED or play a sound)
                    }
                }
            }
        }

        gpioDelay(5000); // Wait before next sweep
    }

    // Cleanup
    printf("Cleaning up...\n");
    gpioServo(SERVO_PIN, 0); // Stop servo
    gpioTerminate(); // Terminate pigpio
    mosquitto_loop_stop(mosq, false);
    mosquitto_disconnect(mosq);
    mosquitto_destroy(mosq);
    mosquitto_lib_cleanup();

    return 0;
}

