    if (fp == NULL) {
        fprintf(stderr, "Error opening file %s\n", filename);
        return -1;
    }

    // Append the JSON data to the file
    fprintf(fp, "%s{", (ftell(fp) == 0) ? "[" : ",");
    fprintf(fp, "\"sensor_id\": %d, ", data->sensor_id);
    fprintf(fp, "\"timestamp_sec\": %ld, ", data->timestamp_sec);
    fprintf(fp, "\"timestamp_usec\": %ld, ", data->timestamp_usec);
