// Function to read temperature and humidity data from the SHT31-D sensor
int read_sensor_data(int fd, float *temperature, float *humidity) {
    unsigned char buf[6];
    int retries = 3;

    // Send measurement command
    while (retries > 0) {
        if (wiringPiI2CWrite(fd, (MEASUREMENT_CMD >> 8) & 0xFF) == 0 &&
            wiringPiI2CWrite(fd, MEASUREMENT_CMD & 0xFF) == 0) {
            break; // Command sent successfully
        } else {
            fprintf(stderr, "Error writing to I2C: %s (retrying...)\n", strerror(errno));
            retries--;
