    retries = 3;
    while (retries > 0) {
        int read_result = wiringPiI2CReadReg8(fd, 0x00, (char *)buf, 6);
        if (read_result == 6) {
            break; // Data read successfully
        } else {
            fprintf(stderr, "Error reading from I2C: %s (retrying...)\n", strerror(errno));
            retries--;
            delay(10); // Wait before retrying
