// VL53L1X register definitions (example - adjust based on datasheet)
#define VL53L1X_REG_IDENTIFICATION_MODEL_ID  0x00C0
#define VL53L1X_REG_IDENTIFICATION_REVISION_ID 0x00C2
#define VL53L1X_REG_DISTANCEMEASURE  0x0089 // Example Register - adjust based on datasheet
#define VL53L1X_REG_INTERMEASUREMENT_PERIOD 0x00E7

// Sensor addresses
#define SENSOR1_ADDR 0x29
#define SENSOR2_ADDR 0x30
#define SENSOR3_ADDR 0x31

#define WARNING_THRESHOLD 200 // mm

// Global variables (minimize usage)
static FILE *log_file = NULL;
static volatile int running = 1;

// Function prototypes
int init_sensor(int address);
int read_distance(int fd);
void trigger_warning(int sensor_id, int distance);
void log_message(const char *message);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    running = 0;
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
    if (log_file != NULL) {
        fclose(log_file);
    }
    exit(0);
}

// Initialize a VL53L1X sensor at the given I2C address
int init_sensor(int address) {
    int fd = wiringPiI2CSetup(address);
    if (fd == -1) {
        fprintf(stderr, "Error: Failed to initialize sensor at address 0x%02X\n", address);
        return -1; // Indicate failure
    }

    // Basic sensor initialization (replace with actual VL53L1X initialization sequence)
    // This is a placeholder - refer to the VL53L1X datasheet for the correct sequence
    int model_id = wiringPiI2CReadReg8(fd, VL53L1X_REG_IDENTIFICATION_MODEL_ID);
    if (model_id != 0xEE) {
        fprintf(stderr, "Error: Invalid model ID (0x%02X) for sensor at address 0x%02X\n", model_id, address);
        close(fd);
        return -1;
    }
    wiringPiI2CWriteReg8(fd, VL53L1X_REG_INTERMEASUREMENT_PERIOD, 0x0B); // Example setting

    printf("Sensor at address 0x%02X initialized successfully.\n", address);
    return fd; // Return the file descriptor
}

// Read the distance from a VL53L1X sensor
int read_distance(int fd) {
    int distance = wiringPiI2CReadReg16(fd, VL53L1X_REG_DISTANCEMEASURE); // Example register
    if (distance < 0) {
        fprintf(stderr, "Error: Failed to read distance. I2C error code: %d\n", distance);
        return -1; // Indicate error
    }

    // Validate the distance reading (example validation)
    if (distance > 4000) { // Maximum range of VL53L1X
        fprintf(stderr, "Warning: Distance reading out of range: %d\n", distance);
        return -1; // Indicate error
    }

    return distance;
}

// Trigger a warning if an object is too close
void trigger_warning(int sensor_id, int distance) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    char message[100];
    snprintf(message, sizeof(message), "%s - WARNING: Sensor %d - Object detected at %d mm!\n", timestamp, sensor_id, distance);

    printf("%s", message);
    log_message(message);
}

// Log a message to the distance_log.txt file
void log_message(const char *message) {
    if (log_file != NULL) {
        fprintf(log_file, "%s", message);
        fflush(log_file); // Ensure immediate write
    } else {
        fprintf(stderr, "Error: Log file is not open.\n");
    }
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Failed to initialize wiringPi.\n");
        return 1;
    }

    // Open the log file in append mode
    log_file = fopen("distance_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening distance_log.txt");
        return 1;
    }

    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize sensors
    int fd1 = init_sensor(SENSOR1_ADDR);
    int fd2 = init_sensor(SENSOR2_ADDR);
    int fd3 = init_sensor(SENSOR3_ADDR);

    if (fd1 == -1 || fd2 == -1 || fd3 == -1) {
        fprintf(stderr, "Error: Failed to initialize one or more sensors.\n");
        fclose(log_file);
        return 1;
    }

    // Main loop
    while (running) {
        int distance1 = read_distance(fd1);
        if (distance1 > 0) {
            printf("Sensor 1: %d mm\n", distance1);
