    gpioSetPullUpDown(TILT_SWITCH_2, PI_PUD_DOWN);
    gpioSetPullUpDown(TILT_SWITCH_3, PI_PUD_DOWN);

    gpioTerminate();
    pthread_mutex_destroy(&log_mutex);
}

