int main(){
    int state = 0;
    int i;
    int gpio = 17;
    int led = 18;
    int err;
    FILE* file;

    if((err = gpioInitialise()) < 0){
        printf("Error initializing pigpio: %d\n", err);
        return 1;
    }

    gpioSetMode(gpio, PI_INPUT);
    gpioSetMode(led, PI_OUTPUT);
    gpioSetPullUpDown(gpio, PI_PUD_UP);

    gpioSetAlertFunc(gpio, gpio_alert);

    if((file = fopen("tilt_log.txt", "a")) == NULL){
        printf("Error opening file: tilt_log.txt\n");
        return 1;
    }

    for(i = 0; i < 100; i++){
        printf("State: %d\n", state);
        gpioWrite(led, state);

        struct tm* ptm;
        time_t now = time(NULL);
        ptm = localtime(&now);

        fprintf(file, "%04d-%02d-%02dT%02d:%02d:%02d\n", ptm->tm_year + 1900, ptm->tm_mon + 1, ptm->tm_mday, ptm->tm_hour, ptm->tm_min, ptm->tm_sec);

        sleep(1);
    }

    fclose(file);
    gpioTerminate();

    return 0;
}

void gpio_alert(int gpio, int level, uint32_t tick, void* user_data){
    if(gpio == 17){
        if(level == PI_LEVEL_LOW){
            if(state == 0) state = 1;
            else if(state == 1) state = 0;
        }
    }
}

