#define VL53L1X_REG_RESULT_RANGE_STATUS 0x0014
#define VL53L1X_REG_RESULT_SPAD_NB_DETECTED 0x002C
#define VL53L1X_REG_RESULT_PEAK_SIGNAL_RATE 0x0050
#define VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE 0x0096

// Structure for sensor data
typedef struct {
    int i2c_address;
    int handle;
    int distance;
    int valid_reading;
    char id[16];
} sensor_t;

// Global variables
static volatile int running = 1;
static int num_sensors = 0;
