// Helper function to get current timestamp
void get_timestamp(char *timestamp)
{
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);
    strftime(timestamp, 20, "%Y-%m-%d %H:%M:%S", timeinfo);
}

// I2C read function with retry
int i2c_read_byte_data(int handle, int i2c_address, int reg) {
    int result, i;
    for (i = 0; i < I2C_RETRY_COUNT; i++) {
        result = i2cReadByteData(handle, reg);
        if (result >= 0) {
            return result;
        }
        gpioDelay(10); // Small delay before retry
    }
    char timestamp[20];
    get_timestamp(timestamp);
    fprintf(stderr, "%s I2C Read Error (Address: 0x%02X, Register: 0x%02X) after %d retries\n", timestamp, i2c_address, reg, I2C_RETRY_COUNT);
    log_event("I2C Read Error", NULL); // Log I2C error
    return -1; // Indicate error
}

// I2C write function with retry
int i2c_write_byte_data(int handle, int i2c_address, int reg, int data) {
    int result, i;
    for (i = 0; i < I2C_RETRY_COUNT; i++) {
        result = i2cWriteByteData(handle, reg, data);
        if (result == 0) {
            return 0;
        }
        gpioDelay(10); // Small delay before retry
    }
    char timestamp[20];
    get_timestamp(timestamp);
    fprintf(stderr, "%s I2C Write Error (Address: 0x%02X, Register: 0x%02X, Data: 0x%02X) after %d retries\n", timestamp, i2c_address, reg, data, I2C_RETRY_COUNT);
    log_event("I2C Write Error", NULL); // Log I2C error
    return -1; // Indicate error
}

// VL53L1X initialization function
int vl53l1x_init_data(int handle, int i2c_address) {
    int status = 0;

    // Example: Set ROI config to ranging mode
    status = i2c_write_byte_data(handle, i2c_address, VL53L1X_REG_ROI_CONFIG_MODE_RANGING, 0x01);
    if (status != 0) {
        return -1;
    }

    // Start the sensor (single shot mode)
    status = i2c_write_byte_data(handle, i2c_address, VL53L1X_REG_START_STOP, 0x01);
    if (status != 0) {
        return -1;
    }

    return 0; // Indicate success
}

// Sensor initialization function
int init_sensor(sensor_t *sensor) {
    char timestamp[20];
    get_timestamp(timestamp);
    if (vl53l1x_init_data(i2c_bus_handle, sensor->i2c_address) != 0) {
        fprintf(stderr, "%s Sensor 0x%02X initialization failed\n", timestamp, sensor->i2c_address);
        log_event("Sensor Initialization Failed", sensor);
        return -1;
    }

    // Verify sensor ID (example - not fully implemented for VL53L1X)
    int sensor_id = i2c_read_byte_data(i2c_bus_handle, sensor->i2c_address, VL53L1X_REG_IDENTIFICATION_ID);
    if (sensor_id < 0) {
        fprintf(stderr, "%s Error reading sensor ID for 0x%02X\n", timestamp, sensor->i2c_address);
        log_event("Error Reading Sensor ID", sensor);
        return -1;
    }

    snprintf(sensor->id, sizeof(sensor->id), "Sensor_0x%02X", sensor->i2c_address);
    printf("%s Sensor %s initialized successfully\n", timestamp, sensor->id);
    return 0;
}

// Sensor reading function
int read_distance(sensor_t *sensor) {
    int distance = -1; // Initialize to an invalid value
    char timestamp[20];
    get_timestamp(timestamp);
    int status = 0;

    // Trigger a single measurement
    status = i2c_write_byte_data(i2c_bus_handle, sensor->i2c_address, VL53L1X_REG_START_STOP, 0x01);
    if (status != 0) {
        fprintf(stderr, "%s Error triggering measurement for %s\n", timestamp, sensor->id);
        sensor->valid_reading = 0;
        log_event("Error Triggering Measurement", sensor);
        return -1;
    }

    gpioDelay(10); // Wait for measurement (adjust as needed)

    // Read the range status
    int range_status = i2c_read_byte_data(i2c_bus_handle, sensor->i2c_address, VL53L1X_REG_RESULT_RANGE_STATUS);
    if (range_status < 0) {
        fprintf(stderr, "%s Error reading range status from %s\n", timestamp, sensor->id);
        sensor->valid_reading = 0;
        log_event("Error Reading Range Status", sensor);
        return -1;
    }

    // Read the distance
    int distance_high = i2c_read_byte_data(i2c_bus_handle, sensor->i2c_address, VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE + 1);
    int distance_low = i2c_read_byte_data(i2c_bus_handle, sensor->i2c_address, VL53L1X_REG_RESULT_FINAL_CROSSTALK_CORRECTED_RANGE);

    if (distance_high < 0 || distance_low < 0) {
        fprintf(stderr, "%s Error reading distance (high/low bytes) from %s\n", timestamp, sensor->id);
        sensor->valid_reading = 0;
        log_event("Error Reading Distance Bytes", sensor);
        return -1;
    }

    distance = (distance_high << 8) | distance_low;

    if (distance < 0 || distance > 8191) {
        fprintf(stderr, "%s Invalid distance reading (%d) from %s\n", timestamp, distance, sensor->id);
        sensor->valid_reading = 0;
        log_event("Invalid Distance Reading", sensor);
        return -1;
    }

    sensor->valid_reading = 1;
    sensor->distance = distance; // Assign read distance
    return 0;
}

// Gate control function
int control_gate(int state) {
    if (gate_state != state) {
        gpioWrite(GATE_CONTROL_PIN, state);
        gate_state = state;
        char *event_type = (state == GATE_OPEN) ? "Gate Open" : "Gate Closed";
        log_event(event_type, NULL); // Log gate event
        return 1; // Indicate state change
    }
    return 0; // No state change
}

// Logging function
void log_event(const char *event_type, sensor_t *sensor) {
    char timestamp[20];
    get_timestamp(timestamp);

    if (sensor != NULL) {
        fprintf(log_file, "%s - %s - Sensor: %s, Distance: %d mm\n", timestamp, event_type, sensor->id, sensor->distance);
    } else {
        fprintf(log_file, "%s - %s\n", timestamp, event_type);
    }
    fflush(log_file); // Ensure immediate write to file
}

