    }
  }

  fprintf(log_file, "Failed to read distance after multiple retries.\n");
  fflush(log_file);
  return -1; // Failure
}

// Function to activate the relay (open or close the door)
void activate_relay(int pin, int state) {
  digitalWrite(pin, state); // HIGH to open, LOW to close
  if (state == HIGH) {
    log_event("Door opened.");
  } else {
    log_event("Door closed.");
  }
}

// Function to log events to a file
void log_event(const char *message) {
  time_t t = time(NULL);
  struct tm tm = *localtime(&t);
  fprintf(log_file, "[%d-%02d-%02d %02d:%02d:%02d] %s\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, message);
  fflush(log_file); // Ensure the log is written immediately
}

