// 2. Define all global constants
#define BCM2708_PERI_BASE        0x20000000
#define GPIO_BASE                (BCM2708_PERI_BASE + 0x200000) /* GPIO controller */
#define PAGE_SIZE                (4*1024)
#define BLOCK_SIZE               (4*1024)

// 3. Define all global variables
int  mem_fd;
char *gpio_mem, *gpio_map;

// 4. Define all function prototypes
void setup();
void loop();
void closeGPIO();

// 5. Define all functions
void setup(){
    /* Setup:
    - open /dev/mem
    - map GPIO memory
    */
    if ((mem_fd = open("/dev/mem", O_RDWR|O_SYNC) ) < 0) {
        fprintf(stderr, "Cannot open /dev/mem: %s\n", strerror(errno));
        exit(1);
    }

    gpio_map = mmap(
        NULL,
        BLOCK_SIZE,
        PROT_READ|PROT_WRITE,
        MAP_SHARED,
        mem_fd,
        GPIO_BASE
    );

    close(mem_fd); // No need to keep mem_fd open after mmap

    if (gpio_map == MAP_FAILED) {
        fprintf(stderr, "mmap error %s\n", strerror(errno));
        exit(1);
    }

    // Always use volatile pointer!
    gpio_mem = (char*)gpio_map;
}

void loop(){
    /* Loop:
    - read the value of the GPIO pin
    - if the pin is low, toggle the GPIO pin
    - wait 500 milliseconds
    */
    int value;
    int toggle_pin = 18;
    int toggle_time = 500;
    int wait_time = 500;

    value = *(gpio_mem + 13);
    value = value & 0x1000;
    if (value == 0){
        *(gpio_mem + 7) = 1 << toggle_pin;
        usleep(toggle_time);
        *(gpio_mem + 10) = 1 << toggle_pin;
    }
    usleep(wait_time);
}

void closeGPIO(){
    /* CloseGPIO:
    - unmap GPIO memory
    - close /dev/mem
    */
    munmap(gpio_map, BLOCK_SIZE);
    close(mem_fd);
}

// 6. Main program
int main(void){
    // 6.1 Setup
    setup();
    // 6.2 Main program
    while(1){
        // 6.2.1 Loop
        loop();
    }
    // 6.3 CloseGPIO
    closeGPIO();
    // 6.4 Close the program
    return 0;
}

