		if (val == DHT_DATA_ERROR) {
			return DHT_DATA_ERROR;
		} else if (val == DHT_READ_ERROR) {
			count_error++;
			if (count_error > 10) {
				return DHT_READ_ERROR;
			}
		} else {
			count_error = 0;
			if ((state == 1) && (val == 0)) {
				break;
			}
			bits[idx] <<= 1;
			bits[idx] |= val;
			idx++;
			if (idx >= 32) {
				idx = 0;
				data[count] = bits[0];
				count++;
				if (count >= 4) {
					break;
				}
			}
		}
	}

	if ((bits[0] + bits[1] + bits[2] + bits[3]) & 0xFF!= bits[4]) {
