// Function to execute a single step on the specified motor
void motor_step(int motor_id, int step) {
    if (step < 0 || step > 7) {
        fprintf(stderr, "Error: Invalid step sequence: %d\n", step);
        log_data("Error: Invalid step sequence: %d\n", step);
        return;
    }

    int in1_pin, in2_pin, in3_pin, in4_pin;

    if (motor_id == 0) {
        in1_pin = motor0_config.in1_pin;
        in2_pin = motor0_config.in2_pin;
        in3_pin = motor0_config.in3_pin;
        in4_pin = motor0_config.in4_pin;
    } else if (motor_id == 1) {
        in1_pin = motor1_config.in1_pin;
        in2_pin = motor1_config.in2_pin;
        in3_pin = motor1_config.in3_pin;
        in4_pin = motor1_config.in4_pin;
    } else {
        fprintf(stderr, "Error: Invalid motor ID: %d\n", motor_id);
        log_data("Error: Invalid motor ID: %d\n", motor_id);
        return;
    }

    gpioWrite(in1_pin, step_sequence[step][0]);
    gpioWrite(in2_pin, step_sequence[step][1]);
    gpioWrite(in3_pin, step_sequence[step][2]);
    gpioWrite(in4_pin, step_sequence[step][3]);
}

// Function to move the plotter head in x and y directions
void move_xy(int x_steps, int y_steps, void (*step_function)(int, int)) {
    int i;
    // Synchronized stepping for diagonal movement
    if (x_steps > 0 && y_steps > 0) {
        for (i = 0; i < x_steps; ++i) {
            step_function(0, i % 8); // Motor 0
            step_function(1, i % 8); // Motor 1
            gpioDelay(2000); // Delay for smooth movement
        }
    } else if (x_steps > 0) {
        for (i = 0; i < x_steps; ++i) {
            step_function(0, i % 8); // Motor 0
            gpioDelay(2000);
        }
    } else if (y_steps > 0) {
        for (i = 0; i < y_steps; ++i) {
            step_function(1, i % 8); // Motor 1
            gpioDelay(2000);
        }
    } else if (x_steps < 0 && y_steps < 0) {
      for (i = 0; i < abs(x_steps); ++i) {
            step_function(0, i % 8); // Motor 0
            step_function(1, i % 8); // Motor 1
            gpioDelay(2000); // Delay for smooth movement
        }
    }

}

// Function to recursively generate the Hilbert curve path
void hilbert_curve(int level, int direction, void (*step_function)(int, int)) {
    if (level == 0) return;

    if (direction == 0) {
        hilbert_curve(level - 1, 1, step_function);
        move_xy(0, 1, step_function);
        hilbert_curve(level - 1, 0, step_function);
        move_xy(1, 0, step_function);
        hilbert_curve(level - 1, 0, step_function);
        move_xy(0, -1, step_function);
        hilbert_curve(level - 1, 3, step_function);
    } else if (direction == 1) {
        hilbert_curve(level - 1, 0, step_function);
        move_xy(1, 0, step_function);
        hilbert_curve(level - 1, 1, step_function);
        move_xy(0, 1, step_function);
        hilbert_curve(level - 1, 1, step_function);
        move_xy(-1, 0, step_function);
        hilbert_curve(level - 1, 2, step_function);
    } else if (direction == 2) {
        hilbert_curve(level - 1, 3, step_function);
        move_xy(0, -1, step_function);
        hilbert_curve(level - 1, 2, step_function);
        move_xy(-1, 0, step_function);
        hilbert_curve(level - 1, 2, step_function);
        move_xy(0, 1, step_function);
        hilbert_curve(level - 1, 1, step_function);
    } else if (direction == 3) {
        hilbert_curve(level - 1, 2, step_function);
        move_xy(-1, 0, step_function);
        hilbert_curve(level - 1, 3, step_function);
        move_xy(0, -1, step_function);
        hilbert_curve(level - 1, 3, step_function);
        move_xy(1, 0, step_function);
        hilbert_curve(level - 1, 0, step_function);
    }
}

// Function to initialize GPIO pins
int initialize_gpio(void) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Error: pigpio initialisation failed\n");
        return 1;
    }

    // Set motor pins as outputs
    gpioSetMode(MOTOR0_IN1, PI_OUTPUT);
    gpioSetMode(MOTOR0_IN2, PI_OUTPUT);
    gpioSetMode(MOTOR0_IN3, PI_OUTPUT);
    gpioSetMode(MOTOR0_IN4, PI_OUTPUT);

    gpioSetMode(MOTOR1_IN1, PI_OUTPUT);
    gpioSetMode(MOTOR1_IN2, PI_OUTPUT);
    gpioSetMode(MOTOR1_IN3, PI_OUTPUT);
    gpioSetMode(MOTOR1_IN4, PI_OUTPUT);

    // Set button pin as input with pull-up resistor
    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetPullUpDown(BUTTON_PIN, PI_PUD_UP);
