// Function to read accelerometer data (example using MPU6050 registers)
int read_accelerometer(float *x, float *y, float *z) {
    char reg[1] = {0x3B}; // Starting register for accelerometer data
    char buf[6];
    int16_t acc_x, acc_y, acc_z;

    if (i2cReadI2CBlockData(i2c_handle, reg[0], buf, 6) != 6) { // Use i2cReadI2CBlockData instead
        fprintf(stderr, "Error: I2C read failed\n");
        log_data("Error: I2C read failed\n");
        return 1;
    }

    acc_x = (int16_t)((buf[0] << 8) | buf[1]);
    acc_y = (int16_t)((buf[2] << 8) | buf[3]);
    acc_z = (int16_t)((buf[4] << 8) | buf[5]);

    // Scale and convert to g-force (adjust scale based on accelerometer)
    *x = (float)acc_x / 16384.0;
    *y = (float)acc_y / 16384.0;
    *z = (float)acc_z / 16384.0;

    return 0;
}

