#include <wiringPiI2C.h>
#include <unistd.h>

#define SHT31_ADDR 0x44
#define MEASURE_CMD 0x2C06
#define LOG_FILE "environmental_log.json"

// Structure to hold sensor data
typedef struct {
    float temperature;
    float humidity;
} SensorData;

// Function to get the current timestamp in ISO 8601 format
char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    char *timestamp = (char*)malloc(21 * sizeof(char)); // YYYY-MM-DDTHH:mm:ssZ\0
    if (timestamp == NULL) {
        perror("Failed to allocate memory for timestamp");
        return NULL;
    }

    time(&rawtime);
    timeinfo = gmtime(&rawtime);

    strftime(timestamp, 21, "%Y-%m-%dT%H:%M:%SZ", timeinfo);
    return timestamp;
}

// Function to read raw temperature and humidity data from the SHT31-DIS sensor
int read_sensor_data(int fd, uint16_t *temperature, uint16_t *humidity) {
    if (wiringPiI2CWrite(fd, MEASURE_CMD >> 8) == -1) {
        perror("Error writing MSB of measure command");
        return -1;
    }
    if (wiringPiI2CWrite(fd, MEASURE_CMD & 0xFF) == -1) {
        perror("Error writing LSB of measure command");
        return -1;
    }

    delay(10); // Wait for measurement

    int temp_msb = wiringPiI2CReadReg16(fd, 0); // Read temperature MSB and LSB
    if (temp_msb == -1) {
        perror("Error reading temperature MSB");
        return -1;
    }
    int hum_msb = wiringPiI2CReadReg16(fd, 2); // Read humidity MSB and LSB
    if (hum_msb == -1) {
        perror("Error reading humidity MSB");
        return -1;
    }

    *temperature = (uint16_t)temp_msb;
    *humidity = (uint16_t)hum_msb;

    return 0;
}

// Function to convert raw sensor data to temperature in Celsius and humidity in percentage
SensorData convert_data(uint16_t raw_temperature, uint16_t raw_humidity) {
    SensorData data;
    data.temperature = -45.0 + (175.0 * (float)raw_temperature / 65535.0);
    data.humidity = 100.0 * (float)raw_humidity / 65535.0;
    return data;
}

// Function to format sensor data into a JSON string
char* format_json(float temperature, float humidity) {
    char *timestamp = get_timestamp();
    if (timestamp == NULL) {
        return NULL;
    }

    char *json_string = (char*)malloc(256 * sizeof(char)); // Allocate memory for the JSON string
    if (json_string == NULL) {
        perror("Failed to allocate memory for JSON string");
        free(timestamp);
        return NULL;
    }

    snprintf(json_string, 256, 
             "{\"timestamp\":\"%s\",\"temperature_celsius\":%.2f,\"humidity_percentage\":%.2f,\"sensor_id\":\"SHT31-DIS_RPiZeroW\"}",
             timestamp, temperature, humidity);

    free(timestamp);
    return json_string;
}

// Function to write the JSON string to the log file
int log_data(const char *json_string) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return -1;
    }

    fprintf(fp, "%s\n", json_string);
    fclose(fp);
    return 0;
}

int main() {
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed: %s\n", strerror(errno));
        return 1;
    }

    int fd = wiringPiI2CSetup(SHT31_ADDR);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed: %s\n", strerror(errno));
        return 1;
    }

    uint16_t raw_temperature, raw_humidity;

    if (read_sensor_data(fd, &raw_temperature, &raw_humidity) == 0) {
        SensorData data = convert_data(raw_temperature, raw_humidity);
        char *json_string = format_json(data.temperature, data.humidity);
        if (json_string != NULL) {
            if (log_data(json_string) != 0) {
                fprintf(stderr, "Failed to log data.\n");
            }
            free(json_string);
        } else {
            fprintf(stderr, "Failed to format JSON.\n");
        }
    } else {
        fprintf(stderr, "Failed to read sensor data.\n");
    }

    return 0;
}

