// Function to initialize I2C communication
int init_i2c(int i2c_bus, int i2c_address) {
    int handle = i2cOpen(i2c_bus, i2c_address, 0);
    if (handle < 0) {
        fprintf(stderr, "Error opening I2C device at address 0x%02X: %d\n", i2c_address, handle);
        return -1;
    }
    return handle;
}

// Function to read temperature and humidity data from SHT31-DIS
int read_sht31_data(int i2c_handle, float *temperature, float *humidity) {
    unsigned char cmd[2] = {(SHT31_MEASURE_HIGH_PRECISION >> 8) & 0xFF, SHT31_MEASURE_HIGH_PRECISION & 0xFF};
    unsigned char data[6];
    int retries = RETRY_COUNT;
    int result;

    while (retries > 0) {
        result = i2cWriteDevice(i2c_handle, cmd, 2);
        if (result == 0) {
            gpioDelay(20); // Wait for measurement (at least 10ms for high precision)
            result = i2cReadDevice(i2c_handle, data, 6);
            if (result == 6) {
                // Convert data to temperature and humidity
                uint16_t temperature_raw = (data[0] << 8) | data[1];
                uint16_t humidity_raw = (data[3] << 8) | data[4];

                *temperature = -45.0 + (175.0 * (float)temperature_raw / 65535.0);
                *humidity = 100.0 * (float)humidity_raw / 65535.0;

                return 0; // Success
            } else {
                fprintf(stderr, "Error reading from I2C device: %d\n", result);
                retries--;
                gpioDelay(RETRY_DELAY_MS);
            }
        } else {
            fprintf(stderr, "Error writing to I2C device: %d\n", result);
            retries--;
            gpioDelay(RETRY_DELAY_MS);
        }
    }

    fprintf(stderr, "Failed to read data from sensor after %d retries.\n", RETRY_COUNT);
    return -1; // Failure
}

// Function to log data to a file
int log_data(FILE *log_file, int sensor_id, float temperature, float humidity) {
    time_t now = time(NULL);
