// Function to generate JSON data
int generate_json(int sensor_id, float temperature, float humidity, char *json_string, size_t json_string_size) {
    json_t *root = json_object();
    json_t *sensor_id_json = json_integer(sensor_id);
    json_t *temperature_json = json_real(temperature);
    json_t *humidity_json = json_real(humidity);
    json_t *timestamp_json = json_integer(time(NULL));

    json_object_set_new(root, "sensor_id", sensor_id_json);
    json_object_set_new(root, "temperature", temperature_json);
    json_object_set_new(root, "humidity", humidity_json);
    json_object_set_new(root, "timestamp", timestamp_json);

    json_t *error = json_string("null");
    json_object_set_new(root, "error", error);

    char *json_str = json_dumps(root, JSON_INDENT(4));
    if (json_str == NULL) {
        fprintf(stderr, "Error generating JSON string\n");
        json_decref(root);
        return -1;
    }

    strncpy(json_string, json_str, json_string_size - 1);
    json_string[json_string_size - 1] = '\0'; // Ensure null termination
    json_decref(root);
    free(json_str);

    return 0;
}

