 int sensor1Value = readSensor(SENSOR1_PIN);
 int sensor2Value = readSensor(SENSOR2_PIN);

 if (sensor1Value == HIGH || sensor2Value == HIGH) {
 // Toggle relay state
 controlRelay(!relayState);

 // Wait for a short period to prevent rapid toggling
 delay(500); // Adjust as needed
 }

 delay(10); // Small delay to prevent busy-waiting
 }

 return 0;
}

