    fprintf(fp, "%s,%d,%d,%d,%d\n", timestamp_str, event.x, event.y, event.z, event.threshold);

    // Close the log file
    fclose(fp);
}

// Function to initialize the I2C communication
void init_i2c()
{
    // Initialize the I2C communication
    int fd = wiringPiI2CSetup(SLAVE_ADDR);

