int read_acceleration(int fd, float *x, float *y, float *z) {
    int16_t x_raw, y_raw, z_raw;

    // Read X axis data
    x_raw = (wiringPiI2CReadReg8(fd, REG_XOUT_L) << 8) | wiringPiI2CReadReg8(fd, REG_XOUT_H);
