/*
 *  C code for Raspberry Pi Zero W
 *  Interface with a VL53L1X time-of-flight sensor via I2C using the `pigpio` library,
 *  triggering distance readings upon detection of motion via a PIR sensor on GPIO 17,
 *  logging distance (mm) and timestamp to a comma-separated file named `distance_log.csv`,
 *  and handling I2C communication errors.
 *
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pigpio.h>
#include <time.h>
#include <math.h>

#define I2C_ADDRESS 0x29
#define PIR_PIN 17

// Function to start I2C communication
void start_i2c() {
    // Check if I2C communication is already running
    if (gpioInitialise() < 0) {
        printf("Error initializing I2C communication!\n");
        exit(-1);
    }
}

// Function to read and verify the response from the VL53L1X
void read_response(int file, int *result) {
    if (result < 0) {
        printf("Error reading VL53L1X response!\n");
        exit(-1);
    }
}

// Function to log timestamp and distance to a comma-separated file
void log_data(double distance) {
    FILE *fp = fopen("distance_log.csv", "a");
    time_t rawtime;
    struct tm *info;
    char buffer[80];

    // Get the current date and time
    time(&rawtime);
    info = localtime(&rawtime);

    // Format the date and time into a string
    strftime(buffer, 80, "%Y-%m-%d %H:%M:%S", info);

    // Write the timestamp and distance to the file
    fprintf(fp, "%s, %f\n", buffer, distance);
    fclose(fp);
}

int main() {
    // Start I2C communication
    start_i2c();

    // Set the PIR pin to be an input
    gpioSetMode(PIR_PIN, PI_INPUT);

    // Set the I2C address of the VL53L1X
    i2cSetDeviceAddress(I2C_ADDRESS);

    // Main loop
    while (1) {
        // Read the PIR sensor
        int pir = gpioRead(PIR_PIN);

        // If motion is detected
        if (pir == 1) {
            // Read the distance from the VL53L1X
            int result = i2cWriteRead(I2C_ADDRESS, 0x010, 2);
            read_response(result);
            uint16_t distance = (result & 0xff) << 8 | (result & 0xff00) >> 8;

            // Convert the distance to millimeters
            double millimeters = distance * 1.27;

            // Log the timestamp and distance to a comma-separated file
            log_data(millimeters);
        }

        // Sleep for 1 second
        gpioSleep(1000);
    }

    // Stop I2C communication
    gpioTerminate();
}

