    // Create socket
    if ((sockfd = socket(AF_INET, SOCK_DGRAM, 0)) < 0) {
        fprintf(stderr, "Socket creation failed: %s\n", strerror(errno));
        return;
    }

    memset(&servaddr, 0, sizeof(servaddr));
    servaddr.sin_family = AF_INET;
    servaddr.sin_port = htons(SERVER_PORT);

    // Convert IPv4 and IPv6 addresses from text to binary form
    if (inet_pton(AF_INET, SERVER_IP, &servaddr.sin_addr) <= 0) {
        fprintf(stderr, "Invalid address / Address not supported: %s\n", strerror(errno));
        close(sockfd);
        return;
    }

    // Send the message
    if (sendto(sockfd, (const char *)message, strlen(message), 0, (const struct sockaddr *)&servaddr, sizeof(servaddr)) < 0) {
        fprintf(stderr, "Sendto failed: %s\n", strerror(errno));
        close(sockfd);
        return;
    }

    fprintf(stdout, "Motion data sent to server: %s\n", message);

    close(sockfd);
}

// Interrupt handler function for motion detection
void motionDetected(void) {
    fprintf(stdout, "Motion detected!\n");
    toggleLED(LED_PIN);
    sendMotionData();
}

int main(void) {
