// Interrupt service routine for motion detection
void motionDetected(void)
{
    int currentMotionState = digitalRead(PIR_PIN);

    // Check for motion transition (rising edge)
    if (currentMotionState == HIGH && previousMotionState == LOW)
    {
        // Toggle the LED
        digitalWrite(LED_PIN,!digitalRead(LED_PIN));

        // Print a message
        printf("Motion detected!\n");
    }

    // Update the previous motion state
