#define BMP180_ADDR_3 0x75

// BMP180 Registers
#define BMP180_REG_CONTROL 0xF4
#define BMP180_REG_MSB 0xF6
#define BMP180_REG_LSB 0xF7
#define BMP180_REG_XLSB 0xF8

// Calibration Data Registers
#define BMP180_REG_CAL_START 0xAA
#define BMP180_REG_CAL_END 0xBF

// Pressure Threshold
#define PRESSURE_THRESHOLD 95000.0 // Pascals

// GPIO Pin for LED
#define LED_PIN 17

// Oversampling Setting (OSS). Higher values give more accurate results but take longer.
#define OSS 0 //0, 1, 2, or 3

// Global variables (to be avoided, but used here for signal handling)
static int i2c_handle_1 = -1;
static int i2c_handle_2 = -1;
static int i2c_handle_3 = -1;
