    float pressure1, pressure2, pressure3;
    int ret;
    bmp180_calibration_data cal_data_1, cal_data_2, cal_data_3;

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C bus for each sensor
    i2c_handle_1 = i2cOpen(1, BMP180_ADDR_1, 0);
    i2c_handle_2 = i2cOpen(1, BMP180_ADDR_2, 0);
    i2c_handle_3 = i2cOpen(1, BMP180_ADDR_3, 0);

    if (i2c_handle_1 < 0 || i2c_handle_2 < 0 || i2c_handle_3 < 0) {
        fprintf(stderr, "Error opening I2C bus\n");
        if (i2c_handle_1 >= 0) i2cClose(i2c_handle_1);
        if (i2c_handle_2 >= 0) i2cClose(i2c_handle_2);
        if (i2c_handle_3 >= 0) i2cClose(i2c_handle_3);
        gpioTerminate();
        return 1;
