#define DEBOUNCE_DELAY_MS 500

// Global variables
FILE *log_file;
volatile sig_atomic_t program_running = 1;

// Function prototypes
void signal_handler(int signal);
void log_event(const char *event);
void close_window();
void open_window();

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    gpioWrite(MOTOR_DIRECTION_PIN, 0); // Stop motor
    gpioPWM(MOTOR_PWM_PIN, 0);         // Stop PWM
    gpioTerminate();                     // Terminate pigpio
    fclose(log_file);                    // Close log file
    printf("\nProgram terminated gracefully.\n");
    exit(0);
}

// Log events to file with timestamp
void log_event(const char *event) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    fprintf(log_file, "[%s] %s\n", timestamp, event);
    fflush(log_file);
    printf("[%s] %s\n", timestamp, event);
}

// Function to close the window
void close_window() {
    log_event("Closing window");
    gpioWrite(MOTOR_DIRECTION_PIN, 1); // Set direction to close

    for (int i = 0; i <= PWM_RANGE; ++i) {
        gpioPWM(MOTOR_PWM_PIN, i);
        gpioDelay(CLOSE_DURATION_SEC * 1000000 / PWM_RANGE); // Scale delay to achieve 5-second close
    }
    log_event("Window closed");
}

// Function to open the window
void open_window() {
    log_event("Opening window");
    gpioWrite(MOTOR_DIRECTION_PIN, 0); // Set direction to open

    for (int i = 0; i <= PWM_RANGE; ++i) {
        gpioPWM(MOTOR_PWM_PIN, i);
        gpioDelay(CLOSE_DURATION_SEC * 1000000 / PWM_RANGE); // Scale delay to achieve 5-second open
    }
    log_event("Window opened");
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open log file
    log_file = fopen("window_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        gpioTerminate();
        return 1;
    }

    // Set GPIO modes
    gpioSetMode(RAIN_SENSOR_PIN, PI_INPUT);
    gpioSetMode(MOTOR_DIRECTION_PIN, PI_OUTPUT);
    gpioSetMode(MOTOR_PWM_PIN, PI_OUTPUT);

    // Enable pull-up resistor on rain sensor pin
    gpioSetPullUpDown(RAIN_SENSOR_PIN, PI_PUD_UP);

    // Set PWM range
    gpioSetPWMrange(MOTOR_PWM_PIN, PWM_RANGE);
    gpioSetPWMfrequency(MOTOR_PWM_PIN, 1000); // Set PWM frequency (adjust as needed)

    // Initialize motor state (window open)
    gpioWrite(MOTOR_DIRECTION_PIN, 0);
    gpioPWM(MOTOR_PWM_PIN, 0);

    // Install signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    log_event("Program started");
    log_event("Window initially open");

    int last_rain_state = 1; // Assume no rain initially (HIGH)
    time_t last_debounce_time = 0;

    // Main loop
    while (program_running) {
        int current_rain_state = gpioRead(RAIN_SENSOR_PIN);
        time_t now = time(NULL);

        if (current_rain_state != last_rain_state) {
            // Debounce the sensor
            if (difftime(now, last_debounce_time) > (DEBOUNCE_DELAY_MS / 1000.0)) {
                if (current_rain_state == 0) { // Rain detected (LOW)
                    log_event("Rain detected");
                    close_window();
                } else { // Rain stopped (HIGH)
                    log_event("Rain stopped");
                    open_window();
                }
                last_rain_state = current_rain_state;
                last_debounce_time = now;
            }
        }
        gpioDelay(100); // Small delay to reduce CPU usage
    }

    return 0;
}

