#define MOTOR_PWM 18
// Define the log file name
#define LOG_FILE "window_log.txt"
// Global variable to indicate program termination
volatile sig_atomic_t terminate = 0;
// Function prototypes
int read_rain_sensor(int gpio_pin);
void open_window();
void close_window();
void log_event(const char *event_type);
void signal_handler(int signal);
// Structure to hold motor state
typedef struct {
    int direction; // 0 for open, 1 for close
    int pwm_value;
} MotorState;
MotorState motor_state = {0, 0}; // Initialize motor state to closed
// Signal handler function
void signal_handler(int signal) {
    printf("Caught signal %d, terminating...\n", signal);
    terminate = 1;
}
// Function to read the rain sensor value
int read_rain_sensor(int gpio_pin) {
    int sensor_value = gpioRead(gpio_pin);
    if (sensor_value < 0) {
        fprintf(stderr, "Error reading sensor on GPIO %d\n", gpio_pin);
        return -1; // Indicate an error
    }
    return sensor_value == 0? 1 : 0; // Assuming LOW indicates rain
}
// Function to open the window
void open_window() {
    printf("Opening window...\n");
    gpioWrite(MOTOR_DIRECTION, 0); // Set motor direction to open
    gpioPWM(MOTOR_PWM, 255);       // Set PWM duty cycle to maximum
    motor_state.direction = 0;
    motor_state.pwm_value = 255;
    log_event("OPEN");
}
// Function to close the window
void close_window() {
    printf("Closing window...\n");
    gpioWrite(MOTOR_DIRECTION, 1); // Set motor direction to close
    gpioPWM(MOTOR_PWM, 255);       // Set PWM duty cycle to maximum
    motor_state.direction = 1;
    motor_state.pwm_value = 255;
    log_event("CLOSE");
}
// Function to log events to a file
void log_event(const char *event_type) {
