    gpioSetMode(RAIN_SENSOR_2, PI_INPUT);
    gpioSetMode(RAIN_SENSOR_3, PI_INPUT);
    gpioSetMode(MOTOR_DIRECTION, PI_OUTPUT);
    gpioSetMode(MOTOR_PWM, PI_OUTPUT);
    // Register signal handlers for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);
    printf("Rain sensor monitoring started. Press Ctrl+C to exit.\n");
    // Main loop
    while (!terminate) {
        // Read rain sensor values
        int sensor1_value = read_rain_sensor(RAIN_SENSOR_1);
        int sensor2_value = read_rain_sensor(RAIN_SENSOR_2);
        int sensor3_value = read_rain_sensor(RAIN_SENSOR_3);
        if (sensor1_value == -1 || sensor2_value == -1 || sensor3_value == -1) {
