#include <arpa/inet.h>
#include <signal.h>
#include <fcntl.h>
#include <sys/select.h>
#include <sys/types.h>
#include <sys/stat.h>

#define DEFAULT_PORT 5000
#define DEFAULT_MAX_CLIENTS 10
#define MAX_BUFFER_SIZE 256
#define LOG_FILE "server.log"

// Global variables
int server_socket = -1;
int client_sockets[DEFAULT_MAX_CLIENTS] = {0};
int num_clients = 0;
int log_fd = -1;

// Function prototypes
void signal_handler(int signum);
int setup_server(int port);
int accept_client(int server_socket, int *client_socket, int max_clients, int *num_clients);
int receive_message(int client_socket, char *buffer, int buffer_size);
int send_message(int client_socket, char *message);
int process_message(char *message);
char* generate_timestamp();
int log_message(char *message);
void handle_client(int client_socket);

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    printf("Caught signal %d, cleaning up...\n", signum);

    // Close the server socket if it's open
    if (server_socket!= -1) {
        close(server_socket);
        printf("Server socket closed.\n");
    }

    // Close client sockets
    for (int i = 0; i < num_clients; i++) {
        if (client_sockets[i]!= -1) {
            close(client_sockets[i]);
            printf("Client socket %d closed.\n", client_sockets[i]);
        }
    }

    // Close the log file if it's open
    if (log_fd!= -1) {
        close(log_fd);
        printf("Log file closed.\n");
    }

    gpioTerminate();
    exit(0);
}

// Setup the server socket
int setup_server(int port) {
    struct sockaddr_in server_address;

    // Create socket
    server_socket = socket(AF_INET, SOCK_STREAM, 0);
    if (server_socket == -1) {
        perror("socket");
        return -1;
    }

    // Configure server address
    server_address.sin_family = AF_INET;
    server_address.sin_addr.s_addr = INADDR_ANY;
    server_address.sin_port = htons(port);

    // Bind socket to address
    if (bind(server_socket, (struct sockaddr*)&server_address, sizeof(server_address)) < 0) {
        perror("bind");
        close(server_socket);
        return -1;
    }

    // Listen for incoming connections
    if (listen(server_socket, DEFAULT_MAX_CLIENTS) < 0) {
        perror("listen");
        close(server_socket);
        return -1;
    }

    printf("Server listening on port %d\n", port);
    return server_socket;
}

// Accept a client connection
int accept_client(int server_socket, int *client_socket, int max_clients, int *num_clients) {
    struct sockaddr_in client_address;
    socklen_t client_address_len = sizeof(client_address);

    // Accept incoming connection
    *client_socket = accept(server_socket, (struct sockaddr*)&client_address, &client_address_len);
    if (*client_socket < 0) {
        perror("accept");
        return -1;
    }

    printf("Client connected from %s:%d\n", inet_ntoa(client_address.sin_addr), ntohs(client_address.sin_port));

    // Add the client socket to the array
    if (*num_clients < max_clients) {
        client_sockets[*num_clients] = *client_socket;
        (*num_clients)++;
    } else {
        fprintf(stderr, "Too many clients. Rejecting connection.\n");
        close(*client_socket);
        *client_socket = -1; // Indicate rejection
        return -1;
    }

    return 0;
}

// Receive a message from a client
int receive_message(int client_socket, char *buffer, int buffer_size) {
    ssize_t bytes_received = recv(client_socket, buffer, buffer_size - 1, 0);
    if (bytes_received < 0) {
        perror("recv");
        return -1;
    } else if (bytes_received == 0) {
        printf("Client disconnected\n");
        return -1; // Indicate disconnection
    }
    buffer[bytes_received] = '\0';
    return 0;
}

// Send a message to a client
int send_message(int client_socket, char *message) {
    ssize_t bytes_sent = send(client_socket, message, strlen(message), 0);
    if (bytes_sent < 0) {
        perror("send");
        return -1;
    }
    return 0;
}

// Process the received message
int process_message(char *message) {
    printf("Received: %s\n", message);
    return 0;
}

// Generate a timestamp string
char* generate_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    static char timestamp[20]; // YYYY-MM-DD HH:MM:SS\0

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp;
}

// Log a message to the log file
int log_message(char *message) {
    char *timestamp = generate_timestamp();
    if (log_fd == -1) {
        fprintf(stderr, "Log file not opened.\n");
        return -1;
    }

    // Write to file using fputs
    char log_entry[256];
    snprintf(log_entry, sizeof(log_entry), "%s: %s\n", timestamp, message);
    if (fputs(log_entry, stderr) == EOF) {
        perror("fputs");
        return -1;
    }
    fflush(stderr); // Ensure immediate write

    return 0;
}

// Handle a client connection
void handle_client(int client_socket) {
    char buffer[MAX_BUFFER_SIZE];
    int bytes_received;
    int shutdown_requested = 0;

    // Receive messages until the client disconnects or shuts down the server
    while ((bytes_received = receive_message(client_socket, buffer, sizeof(buffer))) == 0 &&!shutdown_requested) {
        // Process the received message
        process_message(buffer);

        // Check if the message contains a shutdown command
        if (strstr(buffer, "SHUTDOWN")!= NULL) {
            printf("Shutdown command received. Shutting down server...\n");
            shutdown_requested = 1;
        }

