        gpioDelay(100000); // Sleep for 100ms
    }

    if (shutdown_requested) {
        // Send a shutdown response
        send_message(client_socket, "Server shutting down. Goodbye.");

        // Close the client socket
        close(client_socket);

        // Remove the socket from the client array
        for (int i = 0; i < num_clients; i++) {
            if (client_sockets[i] == client_socket) {
                client_sockets[i] = -1; // Mark as closed
                break;
            }
        }
    }
}

