#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <pigpio.h>
#include <time.h>
#include <signal.h>
#include <string.h>
#include <unistd.h>
#include <errno.h>

// BME280 I2C address
#define BME280_I2C_ADDR 0x76

// BME280 register addresses
#define BME280_REG_TEMP_MSB 0xFA
#define BME280_REG_PRESS_MSB 0xF7
#define BME280_REG_HUM_MSB 0xFD
#define BME280_REG_CTRL_MEAS 0xF4
#define BME280_REG_CTRL_HUM 0xF2
#define BME280_REG_CONFIG 0xF5
#define BME280_REG_CALIB_00 0x88

// File names
#define SENSOR_STATE_FILE "sensor_state.dat"
#define SENSOR_DATA_FILE "sensor_data.log"

// Global variables
int i2c_handle;
int running = 1;

// Calibration parameters
struct bme280_calib_data {
    uint16_t dig_T1;
    int16_t dig_T2;
    int16_t dig_T3;
    uint16_t dig_P1;
    int16_t dig_P2;
    int16_t dig_P3;
    int16_t dig_P4;
    int16_t dig_P5;
    int16_t dig_P6;
    int16_t dig_P7;
    int16_t dig_P8;
    int16_t dig_P9;
    uint8_t dig_H1;
    int16_t dig_H2;
    uint8_t dig_H3;
    int16_t dig_H4;
    int16_t dig_H5;
    uint8_t dig_H6;
};
struct bme280_calib_data calib;

// Compensation functions (from BME280 datasheet)
int32_t t_fine;

int32_t compensate_temperature(int32_t adc_T) {
    int32_t var1, var2, T;
    var1 = ((((adc_T >> 3) - ((int32_t)calib.dig_T1 << 1))) * ((int32_t)calib.dig_T2)) >> 11;
    var2 = (((((adc_T >> 4) - ((int32_t)calib.dig_T1)) * ((adc_T >> 4) - ((int32_t)calib.dig_T1))) >> 12) * ((int32_t)calib.dig_T3)) >> 14;
    t_fine = var1 + var2;
    T = (t_fine * 5 + 128) >> 8;
    return T;
}

uint32_t compensate_pressure(int32_t adc_P) {
    int64_t var1, var2, p;
    var1 = ((int64_t)t_fine) - 128000;
    var2 = var1 * var1 * (int64_t)calib.dig_P6;
    var2 = var2 + ((var1 * (int64_t)calib.dig_P5) << 17);
    var2 = var2 + (((int64_t)calib.dig_P4) << 35);
    var1 = (var1 * var1 * (int64_t)calib.dig_P3) >> 8;
    var1 = var1 + ((var1 * (int64_t)calib.dig_P2) << 12);
    var1 = var1 + (((int64_t)calib.dig_P1) << 47);
    p = (((int64_t)1048576 - adc_P) * 3125) - var1;
    if (p < 0) return 0;
    var1 = (((int64_t)calib.dig_P9) * (p >> 13) * (p >> 13)) >> 25;
    var2 = (((int64_t)calib.dig_P8) * p) >> 19;
    p = ((p + var1 + var2) >> 8) + (((int64_t)calib.dig_P7) << 4);
    return (uint32_t)p;
}

uint32_t compensate_humidity(int32_t adc_H) {
    int32_t var1;
    var1 = (t_fine - ((int32_t)76800));
    var1 = (((((adc_H << 14) - (((int32_t)calib.dig_H4) << 20) - (((int32_t)calib.dig_H5) * var1)) + ((int32_t)16384)) >> 15) * (((((((var1 * ((int32_t)calib.dig_H6)) >> 10) * (((var1 * ((int32_t)calib.dig_H3)) >> 11) + ((int32_t)32768))) >> 10) + ((int32_t)2097152)) * ((int32_t)calib.dig_H2) + 8192) >> 14));
    var1 = (var1 - (((((var1 >> 15) * (var1 >> 15)) >> 7) * ((int32_t)calib.dig_H1)) >> 4));
    if (var1 < 0) var1 = 0;
    if (var1 > 419430400) var1 = 419430400;
    return (uint32_t)(var1 >> 12);
}


// Function to read calibration data from the sensor
int read_calibration_data() {
    char data[26];
    if (i2cReadI2CBlockData(i2c_handle, BME280_REG_CALIB_00, data, 26) < 0) {
        perror("Failed to read calibration data from sensor");
        return -1;
    }

    calib.dig_T1 = data[0] | (data[1] << 8);
    calib.dig_T2 = (int16_t)(data[2] | (data[3] << 8));
    calib.dig_T3 = (int16_t)(data[4] | (data[5] << 8));
    calib.dig_P1 = data[6] | (data[7] << 8);
    calib.dig_P2 = (int16_t)(data[8] | (data[9] << 8));
    calib.dig_P3 = (int16_t)(data[10] | (data[11] << 8));
    calib.dig_P4 = (int16_t)(data[12] | (data[13] << 8));
    calib.dig_P5 = (int16_t)(data[14] | (data[15] << 8));
    calib.dig_P6 = (int16_t)(data[16] | (data[17] << 8));
    calib.dig_P7 = (int16_t)(data[18] | (data[19] << 8));
    calib.dig_P8 = (int16_t)(data[20] | (data[21] << 8));
    calib.dig_P9 = (int16_t)(data[22] | (data[23] << 8));
    calib.dig_H1 = data[25];

    char data_h[7];
    if (i2cReadI2CBlockData(i2c_handle, 0xE1, data_h, 7) < 0) {
        perror("Failed to read humidity calibration data from sensor");
        return -1;
    }

    calib.dig_H2 = (int16_t)(data_h[0] | (data_h[1] << 8));
    calib.dig_H3 = data_h[2];
    calib.dig_H4 = (int16_t)((data_h[3] << 4) | (data_h[4] & 0x0F));
    calib.dig_H5 = (int16_t)((data_h[5] << 4) | ((data_h[4] >> 4) & 0x0F));
    calib.dig_H6 = data_h[6];

    return 0;
}

// Function to restore sensor state from file
int restore_sensor_state() {
    FILE *fp = fopen(SENSOR_STATE_FILE, "rb");
    if (fp == NULL) {
        perror("Failed to open sensor state file, reading from sensor");
        return read_calibration_data();
    }

    if (fread(&calib, sizeof(struct bme280_calib_data), 1, fp) != 1) {
        perror("Failed to read sensor state from file, reading from sensor");
        fclose(fp);
        return read_calibration_data();
    }

    fclose(fp);
    printf("Sensor state restored from file.\n");
    return 0;
}

// Function to read raw BME280 data
int read_bme280_data(int32_t *temperature, int32_t *pressure, int32_t *humidity) {
    char data[8];

    // Set the sensor to forced mode
    if (i2cWriteByteData(i2c_handle, BME280_REG_CTRL_MEAS, 0b00100101) < 0) { // Temperature x1, Pressure x1, Forced mode
        perror("Failed to set sensor mode");
        return -1;
    }
    if (i2cWriteByteData(i2c_handle, BME280_REG_CTRL_HUM, 0b00000101) < 0) { // Humidity x1
        perror("Failed to set humidity control");
        return -1;
    }
    gpioDelay(100); // Wait for measurement to complete (adjust as needed)

    if (i2cReadI2CBlockData(i2c_handle, BME280_REG_PRESS_MSB, data, 8) < 0) {
        perror("Failed to read data from sensor");
        return -1;
    }

    *pressure = (data[0] << 12) | (data[1] << 4) | (data[2] >> 4);
    *temperature = (data[3] << 12) | (data[4] << 4) | (data[5] >> 4);
    *humidity = (data[6] << 8) | data[7];

    return 0;
}

// Function to log sensor data to file
int log_sensor_data(float temperature, float humidity, float pressure) {
    FILE *fp = fopen(SENSOR_DATA_FILE, "a");
    if (fp == NULL) {
        perror("Failed to open sensor data file");
        return -1;
    }

    // Write header if the file is new
    fseek(fp, 0, SEEK_END);
    long fsize = ftell(fp);
    if (fsize == 0) {
        fprintf(fp, "timestamp,temperature,humidity,pressure\n");
    }

    // Get current timestamp
    time_t t = time(NULL);
    struct tm *tm = localtime(&t);
    char timestamp[64];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm);

    // Log the data
    fprintf(fp, "%s,%.2f,%.2f,%.2f\n", timestamp, temperature, humidity, pressure);

    fclose(fp);
    return 0;
}

// Function to save sensor state to file
int save_sensor_state() {
    FILE *fp = fopen(SENSOR_STATE_FILE, "wb");
    if (fp == NULL) {
        perror("Failed to open sensor state file for writing");
        return -1;
    }

    if (fwrite(&calib, sizeof(struct bme280_calib_data), 1, fp) != 1) {
        perror("Failed to write sensor state to file");
        fclose(fp);
        return -1;
    }

    fclose(fp);
    printf("Sensor state saved to file.\n");
    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    running = 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C device
    i2c_handle = i2cOpen(1, BME280_I2C_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    // Restore sensor state
    if (restore_sensor_state() != 0) {
        fprintf(stderr, "Failed to restore sensor state, using default values.\n");
    }

    // Set signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    time_t last_save_time = time(NULL);

    // Main loop
    while (running) {
        int32_t raw_temperature, raw_pressure, raw_humidity;

        // Read sensor data
        if (read_bme280_data(&raw_temperature, &raw_pressure, &raw_humidity) == 0) {
            // Compensate data
            float temperature = compensate_temperature(raw_temperature) / 100.0;
            float pressure = compensate_pressure(raw_pressure) / 100.0;
            float humidity = compensate_humidity(raw_humidity) / 1024.0;

            // Log data
            if (log_sensor_data(temperature, humidity, pressure) != 0) {
                fprintf(stderr, "Failed to log sensor data.\n");
            }

            printf("Temperature: %.2f °C, Humidity: %.2f %%, Pressure: %.2f hPa\n", temperature, humidity, pressure);
        } else {
            fprintf(stderr, "Failed to read sensor data.\n");
        }

        // Save sensor state periodically (every 3600 seconds = 1 hour)
        time_t current_time = time(NULL);
        if (difftime(current_time, last_save_time) >= 3600) {
            if (save_sensor_state() != 0) {
                fprintf(stderr, "Failed to save sensor state.\n");
            }
            last_save_time = current_time;
        }

        // Sleep for 60 seconds
        gpioSleep(PI_TIME_RELATIVE, 1, 0); // seconds, microseconds
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

