#define SSD1306_SET_VCOM_DESEL 0xDB

#define SSD1306_SET_LOW_COL 0x00
#define SSD1306_SET_HIGH_COL 0x10

static const uint8_t init_commands[] = {
    SSD1306_SET_DISP | 0x00,
    SSD1306_SET_MEMORY_ADDR_MODE | 0x00,
    SSD1306_SET_MUX_RATIO | 0x3F,
    SSD1306_SET_DISPLAY_OFFSET | 0x00,
    SSD1306_SET_START_LINE | 0x00,
    SSD1306_SET_CHARGE_PUMP | 0x14,
    SSD1306_SET_SEGMENT_REMAP | 0x01,
    SSD1306_SET_COM_OUT_DIR | 0x08,
