    SSD1306_SET_PRECHARGE | 0x22,
    SSD1306_SET_COM_PIN_CFG | 0x12,
    SSD1306_SET_CONTRAST | 0xCF,
    SSD1306_SET_ENTIRE_ON,
    SSD1306_SET_NORM_INV,
    SSD1306_SET_DISP | 0x01
};

void i2c_start(int i2c_fd)
{
    int err = i2c_write_quick(i2c_fd, 0);
    if (err)
        fprintf(stderr, "i2c start error: %d\n", err);
}

void i2c_stop(int i2c_fd)
{
    int err = i2c_write_quick(i2c_fd, 1);
    if (err)
        fprintf(stderr, "i2c stop error: %d\n", err);
}

void i2c_write_byte(int i2c_fd, uint8_t data)
{
    int err = i2c_write_byte(i2c_fd, data);
    if (err)
        fprintf(stderr, "i2c write error: %d\n", err);
}

void i2c_write_bytes(int i2c_fd, uint8_t *data, size_t length)
{
    for (size_t i = 0; i < length; i++)
        i2c_write_byte(i2c_fd, data[i]);
}

void oled_init(int i2c_fd)
{
    i2c_start(i2c_fd);
    i2c_write_byte(i2c_fd, 0x00);
    i2c_write_bytes(i2c_fd, init_commands, sizeof(init_commands));
    i2c_stop(i2c_fd);
}

void oled_write_byte(int i2c_fd, uint8_t data)
{
    i2c_start(i2c_fd);
    i2c_write_byte(i2c_fd, 0x40);
    i2c_write_byte(i2c_fd, data);
    i2c_stop(i2c_fd);
}

void oled_write_buffer(int i2c_fd, uint8_t *buffer, size_t length)
{
    i2c_start(i2c_fd);
    i2c_write_byte(i2c_fd, 0x40);
    for (size_t i = 0; i < length; i++)
        i2c_write_byte(i2c_fd, buffer[i]);
    i2c_stop(i2c_fd);
}

void oled_clear_buffer(uint8_t *buffer)
{
    memset(buffer, 0x00, SSD1306_BUFFER_SIZE);
}

void oled_clear_screen(int i2c_fd)
{
    uint8_t buffer[SSD1306_BUFFER_SIZE];
    oled_clear_buffer(buffer);
    oled_write_buffer(i2c_fd, buffer, SSD1306_BUFFER_SIZE);
}

void oled_draw_pixel(uint8_t *buffer, uint8_t x, uint8_t y, uint8_t color)
{
    if (x >= SSD1306_WIDTH || y >= SSD1306_HEIGHT)
        return;

    uint8_t offset = y * SSD1306_WIDTH + x;
    uint8_t mask = 1 << (offset % 8);

    if (color == WHITE)
        buffer[offset / 8] |= mask;
    else
        buffer[offset / 8] &= ~mask;
}

void oled_draw_line(uint8_t *buffer, uint8_t x0, uint8_t y0, uint8_t x1, uint8_t y1, uint8_t color)
{
    if (x0 == x1) {
        if (y0 > y1) {
            uint8_t t = y0;
            y0 = y1;
            y1 = t;
        }

        for (uint8_t y = y0; y <= y1; y++)
            oled_draw_pixel(buffer, x0, y, color);
    } else if (y0 == y1) {
        if (x0 > x1) {
            uint8_t t = x0;
            x0 = x1;
            x1 = t;
        }

        for (uint8_t x = x0; x <= x1; x++)
            oled_draw_pixel(buffer, x, y0, color);
    }
}

void oled_draw_rect(uint8_t *buffer, uint8_t x, uint8_t y, uint8_t width, uint8_t height, uint8_t color)
{
    for (uint8_t i = 0; i < width; i++) {
        oled_draw_pixel(buffer, x + i, y, color);
        oled_draw_pixel(buffer, x + i, y + height - 1, color);
    }

    for (uint8_t i = 0; i < height; i++) {
        oled_draw_pixel(buffer, x, y + i, color);
        oled_draw_pixel(buffer, x + width - 1, y + i, color);
    }
}

void oled_draw_char(uint8_t *buffer, uint8_t x, uint8_t y, char ch, uint8_t color)
{
    uint8_t index = ch -'';
    uint8_t data = font[index];

    for (uint8_t i = 0; i < 5; i++) {
        uint8_t mask = data & 0x10;
        oled_draw_pixel(buffer, x + i, y, mask? color : BLACK);
        data <<= 1;
    }

    for (uint8_t i = 0; i < 5; i++) {
        uint8_t mask = data & 0x10;
        oled_draw_pixel(buffer, x + i, y + 1, mask? color : BLACK);
        data <<= 1;
    }

    for (uint8_t i = 0; i < 5; i++) {
        uint8_t mask = data & 0x10;
        oled_draw_pixel(buffer, x + i, y + 2, mask? color : BLACK);
        data <<= 1;
    }
}

void oled_draw_string(uint8_t *buffer, uint8_t x, uint8_t y, char *str, uint8_t color)
{
    for (uint8_t i = 0; i < strlen(str); i++)
        oled_draw_char(buffer, x + i * 6, y, str[i], color);
}

void oled_display_buffer(int i2c_fd, uint8_t *buffer)
{
    i2c_start(i2c_fd);
    i2c_write_byte(i2c_fd, 0x00);
    i2c_write_bytes(i2c_fd, buffer, SSD1306_BUFFER_SIZE);
    i2c_stop(i2c_fd);
}

int main(int argc, char *argv[])
{
    int i2c_fd = i2c_open(1, I2C_ADDRESS, 0);
    if (i2c_fd < 0) {
        fprintf(stderr, "Failed to open I2C bus: %d\n", i2c_fd);
        return 1;
    }

    oled_init(i2c_fd);
    oled_clear_screen(i2c_fd);

    char *message = "Hello, OLED!";
    uint8_t buffer[SSD1306_BUFFER_SIZE];
    oled_clear_buffer(buffer);
    oled_draw_string(buffer, 2, 2, message, WHITE);
    oled_display_buffer(i2c_fd, buffer);

    i2c_close(i2c_fd);
    return 0;
}

