#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <unistd.h>
#include <pigpio.h>

#define GPIO_LED 24
#define I2C_ADDR 0x23

/*
 * I2C read operation.
 *
 * Input:
 *      char *i2c_bus:      I2C bus.
 *      int address:        I2C slave address.
 *      int reg_addr:       I2C register address.
 *      uint8_t *buffer:    Buffer for data read from I2C.
 *      int length:         Buffer length.
 * Output:
 *      int:                Status code.
 *
 * Returns status code for the read operation.
 */
static int i2c_read(char *i2c_bus, int address, int reg_addr, uint8_t *buffer, int length)
{
    int fd;
    char command[128];

    fd = open(i2c_bus, O_RDWR);
    if (fd < 0) {
        printf("ERROR: Could not open I2C bus %s\n", i2c_bus);
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, address) < 0) {
        printf("ERROR: Could not select I2C slave device %d\n", address);
        return -1;
    }

    sprintf(command, "i2cset -y %d %d 0x%02X", fd, reg_addr, 0x10);
    system(command);

    if (read(fd, buffer, length)!= length) {
        printf("ERROR: Could not read from I2C slave device %d\n", address);
        return -1;
    }

    close(fd);
    return 0;
}

/*
 * I2C write operation.
 *
 * Input:
 *      char *i2c_bus:      I2C bus.
 *      int address:        I2C slave address.
 *      int reg_addr:       I2C register address.
 *      uint8_t *buffer:    Buffer for data written to I2C.
 *      int length:         Buffer length.
 * Output:
 *      int:                Status code.
 *
 * Returns status code for the write operation.
 */
static int i2c_write(char *i2c_bus, int address, int reg_addr, uint8_t *buffer, int length)
