 *
 * Returns status code for the add operation.
 */
int add_node_to_beginning(struct node **head, int data)
{
    struct node *new_node = create_node(data);
    if (new_node == NULL) {
        return FALSE;
    }

    new_node->next = *head;
    *head = new_node;

    return TRUE;
}

