// Define the GPIO pin connected to the vibration sensor
#define VIBRATION_SENSOR_PIN 17

// Debounce delay in milliseconds
#define DEBOUNCE_DELAY 50

// Flag to indicate if a shutdown has already been initiated
volatile sig_atomic_t shutdown_initiated = 0;

// Function to get the current timestamp as a string
char* get_timestamp() {
    time_t now = time(NULL);
    struct tm *tstruct = localtime(&now);
    static char buf[80]; // Static buffer to hold the timestamp
    strftime(buf, sizeof(buf), "%Y-%m-%d %X", tstruct);
    return buf;
}

// Function to handle the vibration sensor interrupt and initiate shutdown
void shutdown_handler() {
    // Debounce the signal
    delay(DEBOUNCE_DELAY);

    // Check if the signal is still low (indicating vibration)
    if (digitalRead(VIBRATION_SENSOR_PIN) == LOW) {
        // Check if shutdown has already been initiated
        if (!shutdown_initiated) {
            shutdown_initiated = 1;

            // Log the vibration event and shutdown initiation to syslog
            syslog(LOG_INFO, "%s: Vibration detected! Initiating shutdown...", get_timestamp());

            // Execute the shutdown command
            if (system("sudo shutdown -h now") != 0) {
                syslog(LOG_ERR, "%s: Failed to initiate shutdown!", get_timestamp());
            } else {
                syslog(LOG_INFO, "%s: Shutdown initiated successfully.", get_timestamp());
            }
        } else {
            syslog(LOG_INFO, "%s: Vibration detected, but shutdown already initiated.", get_timestamp());
        }
    }
}

// Function to handle signals (SIGINT, SIGTERM) for a clean exit
void signal_handler(int sig) {
    syslog(LOG_INFO, "%s: Received signal %d, terminating gracefully.", get_timestamp(), sig);
    closelog();
    exit(0);
}

int main() {
    // Open syslog for logging
    openlog("vibration_shutdown", LOG_PID | LOG_CONS, LOG_USER);

    // Log program startup
    syslog(LOG_INFO, "%s: Vibration shutdown program started.", get_timestamp());

    // Initialize wiringPi
    if (wiringPiSetupSys() == -1) {
        syslog(LOG_ERR, "%s: Failed to initialize wiringPi!", get_timestamp());
        closelog();
        return 1;
    }

    // Set the vibration sensor pin as an input
    pinMode(VIBRATION_SENSOR_PIN, INPUT);

    // Attach an interrupt to the vibration sensor pin
    if (wiringPiISR(VIBRATION_SENSOR_PIN, INT_EDGE_FALLING, shutdown_handler) < 0) {
        syslog(LOG_ERR, "%s: Unable to setup ISR!", get_timestamp());
        closelog();
        return 1;
    }

    // Set up signal handlers for SIGINT and SIGTERM
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main program loop (wait for interrupts)
