#define I2C_BUS 1
#define I2C_ADDR 0x1E
#define I2C_REG_X_MSB 0x01
#define I2C_REG_X_LSB 0x02
#define I2C_REG_Y_MSB 0x03
#define I2C_REG_Y_LSB 0x04
#define I2C_REG_Z_MSB 0x05
#define I2C_REG_Z_LSB 0x06
#define I2C_REG_STATUS 0x09
#define I2C_REG_ID_A 0x0A
#define I2C_REG_ID_B 0x0B
#define I2C_REG_ID_C 0x0C

#define LED_PIN 18
#define LED_PWM_FREQ 500
#define I2C_FREQ 50

void getHeading(int16_t x, int16_t y, int16_t z, float *heading, float *pitch, float *roll);

int main() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "gpioInitialise failed\n");
        return 1;
    }

    if (gpioSetMode(LED_PIN, PI_OUTPUT) < 0) {
        fprintf(stderr, "gpioSetMode failed\n");
        return 1;
    }

    if (gpioSetPWMfrequency(LED_PIN, LED_PWM_FREQ) < 0) {
        fprintf(stderr, "gpioSetPWMfrequency failed\n");
        return 1;
    }

    int fd = i2cOpen(I2C_BUS, I2C_ADDR, 0);
    if (fd < 0) {
        fprintf(stderr, "i2cOpen failed\n");
        return 1;
    }

    if (i2cSetClock(fd, I2C_FREQ) < 0) {
        fprintf(stderr, "i2cSetClock failed\n");
        return 1;
    }

    if (i2cWriteByteData(fd, I2C_REG_ID_A, 0x00) < 0) {
        fprintf(stderr, "i2cWriteByteData failed\n");
        return 1;
    }

    if (i2cWriteByteData(fd, I2C_REG_ID_B, 0x00) < 0) {
        fprintf(stderr, "i2cWriteByteData failed\n");
        return 1;
    }

    if (i2cWriteByteData(fd, I2C_REG_ID_C, 0x48) < 0) {
        fprintf(stderr, "i2cWriteByteData failed\n");
        return 1;
    }

    if (i2cWriteByteData(fd, I2C_REG_CONFIG_A, 0x70) < 0) {
        fprintf(stderr, "i2cWriteByteData failed\n");
        return 1;
    }

    if (i2cWriteByteData(fd, I2C_REG_CONFIG_B, 0xA0) < 0) {
        fprintf(stderr, "i2cWriteByteData failed\n");
        return 1;
    }

    if (i2cWriteByteData(fd, I2C_REG_MODE, 0x00) < 0) {
        fprintf(stderr, "i2cWriteByteData failed\n");
        return 1;
    }

    int16_t x, y, z;
    float heading, pitch, roll;

    while (1) {
        x = i2cReadByteData(fd, I2C_REG_X_MSB);
        y = i2cReadByteData(fd, I2C_REG_Y_MSB);
        z = i2cReadByteData(fd, I2C_REG_Z_MSB);

        getHeading(x, y, z, &heading, &pitch, &roll);

        if (i2cReadByteData(fd, I2C_REG_STATUS) & 0x01) {
            printf("HMC5883L overflow\n");
        } else if (i2cReadByteData(fd, I2C_REG_STATUS) & 0x02) {
            printf("HMC5883L reading\n");
        } else if (i2cReadByteData(fd, I2C_REG_STATUS) & 0x04) {
            printf("HMC5883L reading\n");
        }

        printf("heading = %.2f pitch = %.2f roll = %.2f\n", heading, pitch, roll);
        printf("x = %d y = %d z = %d\n", x, y, z);

        if (heading > 360.0) {
            heading -= 360.0;
        } else if (heading < 0.0) {
            heading += 360.0;
        }

        if (heading > 360.0) {
            heading -= 360.0;
        } else if (heading < 0.0) {
            heading += 360.0;
        }

        if (heading > 0.0 && heading < 22.5) {
            printf("N\n");
        } else if (heading > 22.5 && heading < 67.5) {
            printf("NE\n");
        } else if (heading > 67.5 && heading < 112.5) {
            printf("E\n");
        } else if (heading > 112.5 && heading < 157.5) {
            printf("SE\n");
        } else if (heading > 157.5 && heading < 202.5) {
            printf("S\n");
        } else if (heading > 202.5 && heading < 247.5) {
            printf("SW\n");
        } else if (heading > 247.5 && heading < 292.5) {
            printf("W\n");
        } else if (heading > 292.5 && heading < 337.5) {
            printf("NW\n");
        } else if (heading > 337.5 && heading < 360.0) {
            printf("N\n");
        } else {
            printf("Error: Heading out of range\n");
        }

        gpioPWM(LED_PIN, (int) (heading / 360.0 * 100.0));

        usleep(250000);
    }

    return 0;
}

void getHeading(int16_t x, int16_t y, int16_t z, float *heading, float *pitch, float *roll) {
    *heading = atan2((double) y, (double) x) * 180 / M_PI;
    *pitch = atan2((double) (z * sin(atan2((double) y, (double) x))), (double) (x * cos(atan2((double) y, (double) x)) - y * sin(atan2((double) y, (double) x)))) * 180 / M_PI;
    *roll = atan2((double) (x * sin(atan2((double) y, (double) x)) + y * cos(atan2((double) y, (double) x))), (double) z) * 180 / M_PI;
}

