    if (i2cWriteByteData(i2c_handle, HMC5883L_MODE, 0x00) < 0) {
        fprintf(stderr, "Error setting measurement mode\n");
        return -1;
    }

    // Set gain to 1.3 (configuration A)
    if (i2cWriteByteData(i2c_handle, HMC5883L_CONFIG_A, 0x70) < 0) { // 0x70 = 8-average, 15 Hz, normal measurement
        fprintf(stderr, "Error setting gain\n");
        return -1;
    }

    // Set data output rate to 50 Hz (configuration B)
    if (i2cWriteByteData(i2c_handle, HMC5883L_CONFIG_B, 0x20) < 0) { // 0x20 = 0.75 Hz
        fprintf(stderr, "Error setting data output rate\n");
        return -1;
    }

    return 0;
}

// Reads magnetometer data from the HMC5883L sensor
int read_magnetometer_data(int i2c_handle, int16_t *x, int16_t *y, int16_t *z) {
    char buf[6];

    if (i2cReadI2CBlockData(i2c_handle, HMC5883L_DATA_X_MSB, buf, 6)!= 6) {
        fprintf(stderr, "Error reading magnetometer data\n");
        return -1;
    }

    *x = (int16_t)((buf[0] << 8) | buf[1]);
    *y = (int16_t)((buf[2] << 8) | buf[3]);
    *z = (int16_t)((buf[4] << 8) | buf[5]);

    return 0;
}

// Calculates the heading in degrees
float calculate_heading(int16_t x, int16_t y) {
    float heading = atan2(y, x) * 180 / M_PI;

    // Correct for heading range
    if (heading < 0) {
        heading += 360;
    }

    return heading;
}

// Controls the LED brightness based on the heading
void control_led_brightness(int gpio_pin, float heading) {
    // Map heading (0-360) to brightness (0-100%)
    int brightness = (int)(heading / 360.0 * 100.0);

    // Limit brightness to 0-100
    if (brightness < 0) {
        brightness = 0;
    } else if (brightness > 100) {
        brightness = 100;
    }

    // Set PWM duty cycle
    gpioPWM(gpio_pin, brightness);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize I2C
    i2c_handle = initialize_i2c(1); // I2C bus 1
    if (i2c_handle < 0) {
        gpioTerminate();
        return 1;
    }

    // Configure HMC5883L sensor
    if (configure_hmc5883l(i2c_handle) < 0) {
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Configure LED pin as output
    gpioSetMode(LED_PIN, PI_OUTPUT);

    // Set PWM range (0-1000)
    gpioSetPWMrange(LED_PIN, 1000);

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    int16_t x, y, z;
    float heading;

    // Main loop
    while (program_running) {
        // Read magnetometer data
        if (read_magnetometer_data(i2c_handle, &x, &y, &z) == 0) {
            // Calculate heading
            heading = calculate_heading(x, y);

            // Control LED brightness
            control_led_brightness(LED_PIN, heading);

            // Print heading (for debugging)
            printf("Heading: %.2f degrees\n", heading);
        } else {
            fprintf(stderr, "Error reading magnetometer data, retrying...\n");
        }

        // Delay
        usleep(100000); // 100ms
    }

    return 0;
}

