#define MPR121_RELEASETH_0 0x42
#define MPR121_FILTERTH_0 0x43

// GPIO pins for LEDs
#define LED_PIN_1 17
#define LED_PIN_2 22
#define LED_PIN_3 27

// I2C handle
int i2c_handle;

// Global variable to track program termination
volatile sig_atomic_t terminate = 0;

// Signal handler for Ctrl+C
void signal_handler(int signal)
{
    printf("\nCaught signal %d, terminating gracefully...\n", signal);
    terminate = 1;
}

// Function to handle I2C errors
void i2c_error_handler(const char *message)
{
    fprintf(stderr, "Error: %s\n", message);
    // Attempt to re-initialize I2C
    i2cClose(i2c_handle);
    i2c_handle = i2cOpen(1, MPR121_ADDR, 0);
    if (i2c_handle < 0)
    {
        fprintf(stderr, "Error re-opening I2C: %d\n", i2c_handle);
        gpioTerminate();
        exit(EXIT_FAILURE);
    }
}

// Function to initialize the MPR121 sensor
int mpr121_init()
{
    // Stop mode
    if (i2cWriteByteData(i2c_handle, MPR121_ECR, 0x00) < 0)
    {
        i2c_error_handler("Failed to stop MPR121");
        return -1;
    }

    // Set electrode touch and release thresholds
    for (int i = 0; i < 12; i++)
    {
        if (i2cWriteByteData(i2c_handle, MPR121_TOUCHTH_0 + 2 * i, 0x10) < 0)
        {
            i2c_error_handler("Failed to set touch threshold");
            return -1;
        }
        if (i2cWriteByteData(i2c_handle, MPR121_RELEASETH_0 + 2 * i, 0x0C) < 0)
        {
            i2c_error_handler("Failed to set release threshold");
            return -1;
        }
    }

    // Configure filter and ECR
    if (i2cWriteByteData(i2c_handle, MPR121_CONFIG1, 0x20) < 0) // Electrode Configuration
    {
        i2c_error_handler("Failed to configure MPR121");
        return -1;
    }
    if (i2cWriteByteData(i2c_handle, MPR121_CONFIG2, 0x01) < 0) // Filter Configuration
    {
        i2c_error_handler("Failed to configure MPR121");
        return -1;
    }
    if (i2cWriteByteData(i2c_handle, MPR121_CONFIG3, 0x01) < 0) // Filter Configuration
    {
        i2c_error_handler("Failed to configure MPR121");
        return -1;
    }
    if (i2cWriteByteData(i2c_handle, MPR121_ECR, 0x0F) < 0) // Enable electrodes 0-11
    {
        i2c_error_handler("Failed to configure MPR121");
        return -1;
    }

    // Start mode
    if (i2cWriteByteData(i2c_handle, MPR121_ECR, 0x10) < 0)
    {
        i2c_error_handler("Failed to start MPR121");
        return -1;
    }

    return 0;
}

// Function to read the touch status from the MPR121 sensor
int mpr121_read_touch_status(uint16_t *touch_status)
{
    int status_low, status_high;

    status_low = i2cReadByteData(i2c_handle, MPR121_TOUCHSTATUS_L);
    if (status_low < 0)
    {
        i2c_error_handler("Failed to read touch status low byte");
        return -1;
    }

    status_high = i2cReadByteData(i2c_handle, MPR121_TOUCHSTATUS_H);
    if (status_high < 0)
    {
        i2c_error_handler("Failed to read touch status high byte");
        return -1;
    }

    *touch_status = (uint16_t)((status_high << 8) | status_low);
    return 0;
}

// Function to select a random LED pin
int select_random_led_pin()
{
    int led_pins[] = {LED_PIN_1, LED_PIN_2, LED_PIN_3};
    int num_leds = sizeof(led_pins) / sizeof(led_pins[0]);
    return led_pins[rand() % num_leds];
}

// Function to set the PWM duty cycle for an LED pin
void set_led_pwm(int led_pin, int duty_cycle)
{
    gpioPWM(led_pin, duty_cycle);
}

// Function to fade an LED pin using PWM
void fade_led(int led_pin, int start_duty_cycle, int end_duty_cycle, int steps, double fade_duration_seconds)
{
    double increment = (double)(end_duty_cycle - start_duty_cycle) / steps;
    double delay_time = fade_duration_seconds / steps;

    for (int i = 0; i <= steps; i++)
    {
        int duty_cycle = (int)(start_duty_cycle + increment * i);
        set_led_pwm(led_pin, duty_cycle);
        gpioDelay(delay_time * 1000); // Delay in microseconds
    }
}

// Function to unfade an LED pin using PWM
void unfade_led(int led_pin, int start_duty_cycle, int end_duty_cycle, int steps, double fade_duration_seconds)
{
    double increment = (double)(start_duty_cycle - end_duty_cycle) / steps;
    double delay_time = fade_duration_seconds / steps;

    for (int i = 0; i <= steps; i++)
    {
        int duty_cycle = (int)(start_duty_cycle - increment * i);
        set_led_pwm(led_pin, duty_cycle);
        gpioDelay(delay_time * 1000); // Delay in microseconds
    }
}

// Function to stop the PWM on an LED pin
void stop_led_pwm(int led_pin)
{
    gpioPWM(led_pin, 0);
}

