// Define GPIO pins connected to the 74HC595
#define LATCH_PIN  0  // GPIO 17
#define CLOCK_PIN  1  // GPIO 18
#define DATA_PIN   2  // GPIO 27

// Seven-segment display patterns for digits 0-9 (common cathode)
const unsigned char digits[] = {
  0x3F, // 0
  0x06, // 1
  0x5B, // 2
  0x4F, // 3
  0x66, // 4
  0x6D, // 5
  0x7D, // 6
  0x07, // 7
  0x7F, // 8
  0x6F  // 9
};

void shiftOut(unsigned char dataPin, unsigned char clockPin, unsigned char data) {
    for (int i = 0; i < 8; i++) {
        digitalWrite(clockPin, LOW);
        digitalWrite(dataPin, (data >> i) & 1);
        digitalWrite(clockPin, HIGH);
    }
}

void displayDigit(int digit) {
    shiftOut(DATA_PIN, CLOCK_PIN, digits[digit]);
    digitalWrite(LATCH_PIN, LOW);
    digitalWrite(LATCH_PIN, HIGH);
}

int main() {
    wiringPiSetup();

    pinMode(LATCH_PIN, OUTPUT);
    pinMode(CLOCK_PIN, OUTPUT);
    pinMode(DATA_PIN, OUTPUT);

    srand(time(NULL)); // Seed the random number generator

    while (1) {
        int randomNumber = rand() % 10; // Generate a random number between 0 and 9
        printf("Displaying: %d\n", randomNumber);
        displayDigit(randomNumber);
        sleep(2); // Wait for 2 seconds
    }

    return 0;
}

