#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <time.h>
#include <pigpio.h>
#include <errno.h>
#include <string.h>

// Sensor and Fan GPIO Pins
#define SENSOR_1_PIN 4
#define SENSOR_2_PIN 5
#define SENSOR_3_PIN 6
#define FAN_PIN 17

// Initial Threshold and Adjustment Parameters
#define INITIAL_THRESHOLD 200.0
#define THRESHOLD_INCREMENT 10.0
#define CONSECUTIVE_EXCEEDANCE_COUNT 5

// Number of Sensors
#define NUM_SENSORS 3

// Global Variables (for signal handling)
volatile sig_atomic_t program_running = 1;
FILE *log_file = NULL;

// Structure to hold sensor data
typedef struct {
    int pin;
    float reading;
    float threshold;
    int exceedance_count;
} sensor_data_t;

// Signal Handler Function
void signal_handler(int signal) {
    program_running = 0;
    fprintf(stderr, "\nCaught signal %d, exiting gracefully...\n", signal);
}

// Function pointer types
typedef float (*read_sensor_func)(int);
typedef int (*compare_threshold_func)(float, float);

// Function to read sensor data (simulated)
float read_sensor(int pin) {
    // Simulate reading from the sensor (0-1023)
    int raw_reading = rand() % 1024;

    // Convert raw reading to ppm (linear approximation)
    float ppm = (float)raw_reading * 0.5 + 50;

    return ppm;
}

// Function to compare sensor reading with threshold
int compare_threshold(float reading, float threshold) {
    return (reading > threshold) ? 1 : 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed: %s\n", strerror(errno));
        return 1;
    }

    // Configure GPIO pins
    gpioSetMode(SENSOR_1_PIN, PI_INPUT);
    gpioSetMode(SENSOR_2_PIN, PI_INPUT);
    gpioSetMode(SENSOR_3_PIN, PI_INPUT);
    gpioSetMode(FAN_PIN, PI_OUTPUT);

    // Initialize sensor data
    sensor_data_t sensors[NUM_SENSORS];
    sensors[0].pin = SENSOR_1_PIN;
    sensors[0].threshold = INITIAL_THRESHOLD;
    sensors[0].exceedance_count = 0;

    sensors[1].pin = SENSOR_2_PIN;
    sensors[1].threshold = INITIAL_THRESHOLD;
    sensors[1].exceedance_count = 0;

    sensors[2].pin = SENSOR_3_PIN;
    sensors[2].threshold = INITIAL_THRESHOLD;
    sensors[2].exceedance_count = 0;

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Open log file
    log_file = fopen("air_quality.log", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    // Write CSV header
    fprintf(log_file, "timestamp,sensor1_ppm,sensor2_ppm,sensor3_ppm,sensor1_threshold,sensor2_threshold,sensor3_threshold,fan_state\n");
    fflush(log_file);

    // Main loop
    while (program_running) {
        struct timespec ts;
        clock_gettime(CLOCK_REALTIME, &ts);
        char timestamp[30]; // Buffer to hold the formatted timestamp
        sprintf(timestamp, "%ld.%06ld", ts.tv_sec, ts.tv_nsec / 1000); // Microsecond precision

        float sensor_readings[NUM_SENSORS];
        int fan_state = 0; // Assume fan is off initially

        // Read sensor data and compare with thresholds
        for (int i = 0; i < NUM_SENSORS; ++i) {
            sensors[i].reading = read_sensor(sensors[i].pin);
            sensor_readings[i] = sensors[i].reading;

            if (compare_threshold(sensors[i].reading, sensors[i].threshold)) {
                sensors[i].exceedance_count++;
                if (sensors[i].exceedance_count >= CONSECUTIVE_EXCEEDANCE_COUNT) {
                    sensors[i].threshold += THRESHOLD_INCREMENT;
                    sensors[i].exceedance_count = 0; // Reset exceedance count after adjustment
                }
                fan_state = 1; // Activate fan if any sensor exceeds threshold
            } else {
                sensors[i].exceedance_count = 0; // Reset exceedance count if reading is below threshold
            }
        }

        // Control the fan
        gpioWrite(FAN_PIN, fan_state);

        // Log data to file
        fprintf(log_file, "%s,%.2f,%.2f,%.2f,%.2f,%.2f,%.2f,%d\n",
                timestamp,
                sensor_readings[0],
                sensor_readings[1],
                sensor_readings[2],
                sensors[0].threshold,
                sensors[1].threshold,
                sensors[2].threshold,
                fan_state);
        fflush(log_file);

        // Delay for 100 milliseconds
        gpioDelay(100);
    }

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    // Terminate pigpio
    gpioTerminate();

    return 0;
}

