int main (void)
{
  int	i, j ;

  // Initialize wiringPi
  if (wiringPiSetup () == -1)
    return 1 ;

  // Initialize the WS2812B library
  ws2812SetPin (18) ;
  ws2812SetNumLeds (NUM_LEDS * NUM_STRIPS) ;

  // Set up the LED data arrays - just a basic red/green/blue sequence
  for (i = 0 ; i < NUM_LEDS ; ++i)
    ledData [i] = ((i & 0x10)? 0x0000FF : 0xFF0000) | ((i & 0x08)? 0x00FF00 : 0x000000) ;

  // And now start the loop
  for (;;)
  {
    for (i = 0 ; i < NUM_STRIPS ; ++i)
    {
      // Send the data to the LED strip
      ws2812Send (ledData + (i * NUM_LEDS), NUM_LEDS) ;

      // Wait 1 second
      delay (1000) ;
    }
  }

  return 0 ;
}


