// Global flag to indicate motion detection
volatile sig_atomic_t motionDetected = 0;

// Function prototypes
void motionDetectedHandler(int gpio, int level, uint32_t tick, void *userdata);
void stopBuzzer(int gpio, int level, uint32_t tick, void *userdata);
void signalHandler(int signal);

// Signal handler to catch SIGINT (Ctrl+C)
void signalHandler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    gpioWrite(BUZZER_PIN, 0); // Ensure buzzer is off
    gpioTerminate();        // Terminate pigpio
    exit(0);                  // Exit the program
}

// Interrupt handler for motion detection
void motionDetectedHandler(int gpio, int level, uint32_t tick, void *userdata) {
    if (level == 1) { // Rising edge detected (motion)
        motionDetected = 1;
        gpioWrite(BUZZER_PIN, 1); // Turn on the buzzer
        gpioSetISRFuncEx(BUZZER_PIN, RISING_EDGE, 0, stopBuzzer, NULL); // Set interrupt on falling edge to stop the buzzer
    }
}

// Interrupt handler to stop the buzzer
void stopBuzzer(int gpio, int level, uint32_t tick, void *userdata) {
    gpioWrite(BUZZER_PIN, 0); // Turn off the buzzer
    motionDetected = 0; // Reset motion detection flag
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Exit with an error code
    }

    // Set GPIO modes
    gpioSetMode(PIR_SENSOR_PIN, PI_INPUT); // PIR sensor pin as input
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);    // Buzzer pin as output

