/* Task:
        You are a Raspberry Pi C Code Expert. Write a C code for Raspberry Pi that accomplishes the following task:
        Write a C program for Raspberry Pi 3 Model B+ to read temperature data from an AM2302 temperature sensor connected to SDA/GPIO 2 and SCL/GPIO 3, logging timestamped temperature data to a file named `temperature_log.txt`, and implementing robust error handling for GPIO initialization failures using the `wiringPi` library.

        Output the C code without any explanations or comments, enclosed in ```c... ``` code blocks, 
        followed by the build command enclosed in ```bash... ``` code blocks. 
        Do not include any text outside the ```c... ``` and ```bash... ``` code blocks.

        */

#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <time.h>
#include <math.h>

#define MAX_LEN 1024
#define I2C_ADDR 0x5C
#define TEMPERATURE_REG 0x00
#define HUMIDITY_REG 0x01

FILE *f;

int main(int argc, char **argv) {
    char timestr[MAX_LEN];
    time_t t;
    struct tm *tm;
    int i, n, pirPin;
    int val;
    int err;
    unsigned char buf[4];
    float humidity, temperature;

    // Check that wiringPi is installed and initialized
    if ((err = wiringPiSetup()) < 0) {
        fprintf (stderr, "Unable to initialize wiringPi: %s\n", strerror (err));
        return 1;
    }

    // Open file
    f = fopen("temperature_log.txt", "w");

    // Check that file opened successfully
    if (f == NULL) {
        fprintf(stderr, "Cannot open file\n");
        return 1;
    }

    // Get I2C bus
    int i2c = wiringPiI2CSetup(I2C_ADDR);

    // Read data from AM2302
    while (1) {
        buf[0] = TEMPERATURE_REG;
        i = wiringPiI2CWrite(i2c, buf, 1);
        sleep(1);
        i = wiringPiI2CRead(i2c, buf, 4);

        // Convert data to humidity and temperature
        humidity = -6.0 + 125.0/65536.0 * (float)((buf[0] << 8) + buf[1]);
        temperature = -46.85 + 175.72/65536.0 * (float)((buf[2] << 8) + buf[3]);

        // Log timestamped temperature and humidity data
        t = time(NULL);
        tm = localtime(&t);
        strftime(timestr, MAX_LEN, "%Y-%m-%d %H:%M:%S", tm);
        fprintf(f, "%s %f %f\n", timestr, temperature, humidity);
        fflush(f);
    }

    // Close file
    fclose(f);

    return 0;
}
