#define NUM_SENSORS 3

// Structure to represent a PIR sensor
typedef struct {
    int gpio_pin;
    void (*motion_callback)(struct PIRSensor*);
} PIRSensor;

// Function prototypes
void motion_detected(PIRSensor *sensor);
void signal_handler(int signal);

// Global variables
PIRSensor sensors[NUM_SENSORS];
FILE *log_file = NULL;

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize sensors
    sensors[0].gpio_pin = 17;
    sensors[0].motion_callback = motion_detected;
    sensors[1].gpio_pin = 18;
    sensors[1].motion_callback = motion_detected;
    sensors[2].gpio_pin = 27;
    sensors[2].motion_callback = motion_detected;

    // Set GPIO pins as inputs and register interrupt handlers
    for (int i = 0; i < NUM_SENSORS; i++) {
        gpioSetMode(sensors[i].gpio_pin, PI_INPUT);
        gpioSetAlertFunc(sensors[i].gpio_pin, motion_detected);
    }

    // Open log file
    log_file = fopen("motion_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        gpioTerminate();
        return 1;
    }

    // Register signal handler for SIGINT (Ctrl+C)
    signal(SIGINT, signal_handler);

    printf("Motion detection started. Press Ctrl+C to exit.\n");

    // Keep the program running until interrupted
    while (1) {
        gpioDelay(1000); // Sleep for 1 second
    }

    return 0;
}

// Motion detection callback function
void motion_detected(PIRSensor *sensor) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    // Log the event to file
    if (log_file != NULL) {
        fprintf(log_file, "%s - Motion detected on GPIO %d\n", timestamp, sensor->gpio_pin);
        fflush(log_file); // Ensure data is written to file immediately
    } else {
        fprintf(stderr, "Error: Log file not opened.\n");
    }

    // Print to console
    printf("%s - Motion detected on GPIO %d\n", timestamp, sensor->gpio_pin);
}

// Signal handler for SIGINT (Ctrl+C)
void signal_handler(int signal) {
    printf("\nCaught signal %d, exiting gracefully...\n", signal);

    // Disable interrupts
    for (int i = 0; i < NUM_SENSORS; i++) {
        gpioSetAlertFunc(sensors[i].gpio_pin, NULL); // Remove interrupt handler
    }

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    // Terminate pigpio library
    gpioTerminate();

    exit(0);
}

