// Define GPIO pins
#define PIR_SENSOR_1 17
#define PIR_SENSOR_2 18
#define RELAY_PIN 27

// Debounce time in milliseconds
#define DEBOUNCE_TIME 50

// Global variable for log file pointer
FILE *log_file = NULL;

// Function prototypes
int initialize_gpio();
int read_pir_sensor(int gpio_pin);
void control_relay(int gpio_pin, int state);
void log_event(const char *event_type, int gpio_pin);
void cleanup_gpio();
void signal_handler(int signal);

// Function to initialize GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    gpioSetMode(PIR_SENSOR_1, PI_INPUT);
    gpioSetMode(PIR_SENSOR_2, PI_INPUT);
    gpioSetMode(RELAY_PIN, PI_OUTPUT);

    // Initialize relay to OFF state (LOW)
    gpioWrite(RELAY_PIN, 0);

    return 0; // Indicate success
}

// Function to read the state of a PIR sensor
int read_pir_sensor(int gpio_pin) {
    return gpioRead(gpio_pin);
}

// Function to control the relay
void control_relay(int gpio_pin, int state) {
    gpioWrite(gpio_pin, state);
}

// Function to log an event to the log file
void log_event(const char *event_type, int gpio_pin) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (log_file!= NULL) {
        fprintf(log_file, "%s - GPIO %d - %s\n", timestamp, gpio_pin, event_type);
        fflush(log_file); // Ensure data is written immediately
    } else {
        fprintf(stderr, "Error: Log file is not open.\n");
    }
}

// Function to cleanup GPIO pins
void cleanup_gpio() {
    gpioWrite(RELAY_PIN, 0); // Ensure relay is OFF on exit
    gpioTerminate();
    if (log_file!= NULL) {
        fclose(log_file);
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    cleanup_gpio();
    exit(0);
}

int main() {
    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize GPIO
    if (initialize_gpio()!= 0) {
        return 1;
    }

    // Open log file in append mode
    log_file = fopen("door_log.txt", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        cleanup_gpio();
        return 1;
    }

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    int last_state_1 = 0;
    int last_state_2 = 0;
    int current_state_1, current_state_2;
    int relay_state = 0; // 0 = OFF, 1 = ON

    // Main loop
    while (1) {
        // Read PIR sensor values
        current_state_1 = read_pir_sensor(PIR_SENSOR_1);
        current_state_2 = read_pir_sensor(PIR_SENSOR_2);

        // Debounce the sensor inputs
        if (current_state_1!= last_state_1) {
            gpioDelay(DEBOUNCE_TIME * 1000); // Delay in microseconds
            current_state_1 = read_pir_sensor(PIR_SENSOR_1);
        }
        if (current_state_2!= last_state_2) {
            gpioDelay(DEBOUNCE_TIME * 1000); // Delay in microseconds
            current_state_2 = read_pir_sensor(PIR_SENSOR_2);
        }

        last_state_1 = current_state_1;
        last_state_2 = current_state_2;

