// Function to read data from the MCP3008 ADC
int read_mcp3008(int spi_fd, int channel) {
    unsigned char tx_buffer[3];
    unsigned char rx_buffer[3];

    // Construct SPI message
    tx_buffer[0] = 0x01;                  // Start bit
    tx_buffer[1] = ((channel & 0x07) << 4) | 0x80; // Single-ended mode, channel selection
    tx_buffer[2] = 0x00;

    struct spi_ioc_transfer transfer = {
       .tx_buf = (unsigned long)tx_buffer,
       .rx_buf = (unsigned long)rx_buffer,
       .len = 3,
       .speed_hz = SPI_SPEED,
       .bits_per_word = SPI_BITS_PER_WORD,
    };

    if (ioctl(spi_fd, SPI_IOC_MESSAGE(1), &transfer) < 0) {
        perror("SPI transfer failed");
        return -1;
    }

    // Extract ADC value (10 bits)
    int adc_value = ((rx_buffer[1] & 0x03) << 8) + rx_buffer[2];

    return adc_value;
}

int main() {
    int spi_fd;
    int adc_value;
    char buffer[100];

    // Open SPI device
    spi_fd = open(SPI_DEVICE, O_RDWR);
    if (spi_fd < 0) {
        perror("Failed to open SPI device");
        return 1;
    }

    // Set SPI mode
    if (ioctl(spi_fd, SPI_IOC_WR_MODE, &SPI_MODE) == -1) {
        perror("Failed to set SPI mode");
        close(spi_fd);
        return 1;
    }

    // Set bits per word
    if (ioctl(spi_fd, SPI_IOC_WR_BITS_PER_WORD, &SPI_BITS_PER_WORD) == -1) {
        perror("Failed to set bits per word");
        close(spi_fd);
        return 1;
    }

    // Set SPI speed
    if (ioctl(spi_fd, SPI_IOC_WR_MAX_SPEED_HZ, &SPI_SPEED) == -1) {
        perror("Failed to set SPI speed");
        close(spi_fd);
        return 1;
    }

    printf("ADC Readings:\n");

    while (1) {
        // Read ADC values from channels 0, 1, and 2
        adc_value = read_mcp3008(spi_fd, 0);
        if (adc_value >= 0) {
            snprintf(buffer, sizeof(buffer), "Channel 0: %d\n", adc_value);
            printf("%s", buffer);
        } else {
            fprintf(stderr, "Error reading ADC value from channel 0\n");
        }

        adc_value = read_mcp3008(spi_fd, 1);
        if (adc_value >= 0) {
            snprintf(buffer, sizeof(buffer), "Channel 1: %d\n", adc_value);
            printf("%s", buffer);
        } else {
            fprintf(stderr, "Error reading ADC value from channel 1\n");
        }

        adc_value = read_mcp3008(spi_fd, 2);
        if (adc_value >= 0) {
            snprintf(buffer, sizeof(buffer), "Channel 2: %d\n", adc_value);
            printf("%s", buffer);
        } else {
            fprintf(stderr, "Error reading ADC value from channel 2\n");
        }

        sleep(1); // Wait for 1 second
    }

    // Close SPI device
    close(spi_fd);

    return 0;
}

