int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    gpioSetMode(PIR_SENSOR_PIN, PI_INPUT);
    gpioSetPullUpDown(PIR_SENSOR_PIN, PI_PUD_DOWN); // Use pull-down resistor

    gpioSetMode(RELAY_PIN, PI_OUTPUT);
    deactivate_relay(); // Ensure relay is initially off

    return 0; // Indicate success
}

// Function to cleanup GPIO pins
void cleanup_gpio() {
    deactivate_relay(); // Ensure relay is off before exiting
    gpioTerminate();
}

// Callback function for motion detection
void motion_detected_callback(int gpio, int level, uint32_t tick) {
    if (level == 1) { // Rising edge detected (motion detected)
        activate_relay();
        log_motion_event();
        gpioDelay(RELAY_ACTIVATION_TIME * 1000000); // Delay for relay activation time
        deactivate_relay();
    }
}

// Function to activate the relay
void activate_relay() {
    if (!relay_active) {
        gpioWrite(RELAY_PIN, 1); // Set relay pin high
        relay_active = 1;
        printf("Relay activated\n");
    }
