#include <pigpio.h>

// Define GPIO pins
#define RELAY_PIN 27

// Define server IP address and port
#define SERVER_IP "192.168.1.100"
#define SERVER_PORT 5000

// Define relay activation time in seconds
#define RELAY_ACTIVATION_TIME 5

// Global variable to track relay state
int relay_active = 0;

// Global variable to store the socket file descriptor
int sockfd = -1;

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    if (sockfd!= -1) {
        close(sockfd);
    }
    deactivate_relay();
    gpioTerminate();
    closelog();
    exit(0);
}

// Function to initialize GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        syslog(LOG_ERR, "pigpio initialisation failed");
        return 1; // Indicate failure
    }

    gpioSetMode(RELAY_PIN, PI_OUTPUT);
    deactivate_relay(); // Ensure relay is initially off

    return 0; // Indicate success
}

// Function to activate the relay
void activate_relay() {
    if (!relay_active) {
        gpioWrite(RELAY_PIN, 1); // Set relay pin high
        relay_active = 1;
        syslog(LOG_INFO, "Relay activated");
    }
}

// Function to deactivate the relay
void deactivate_relay() {
    if (relay_active) {
        gpioWrite(RELAY_PIN, 0); // Set relay pin low
        relay_active = 0;
        syslog(LOG_INFO, "Relay deactivated");
    }
}

// Function to send a message to the server
int send_message(const char *message) {
    if (send(sockfd, message, strlen(message), 0) < 0) {
        syslog(LOG_ERR, "Error sending message: %s", strerror(errno));
        return 1; // Indicate failure
    }
    syslog(LOG_INFO, "Message sent: %s", message);
    return 0; // Indicate success
}

// Function to receive a message from the server
int receive_message(char *buffer, size_t buffer_size) {
    ssize_t bytes_received = recv(sockfd, buffer, buffer_size - 1, 0);
    if (bytes_received < 0) {
        syslog(LOG_ERR, "Error receiving message: %s", strerror(errno));
        return 1; // Indicate failure
    } else if (bytes_received == 0) {
        syslog(LOG_INFO, "Server disconnected");
        return 2; // Indicate server disconnected
    }
    buffer[bytes_received] = '\0';
    syslog(LOG_INFO, "Message received: %s", buffer);
    return 0; // Indicate success
}

// Function to connect to the server
int connect_to_server() {
    struct sockaddr_in serv_addr;

    sockfd = socket(AF_INET, SOCK_STREAM, 0);
    if (sockfd < 0) {
        syslog(LOG_ERR, "Error creating socket: %s", strerror(errno));
        return 1; // Indicate failure
    }

    serv_addr.sin_family = AF_INET;
    serv_addr.sin_port = htons(SERVER_PORT);

    // Convert IPv4 and IPv6 addresses from text to binary form
    if (inet_pton(AF_INET, SERVER_IP, &serv_addr.sin_addr) <= 0) {
        syslog(LOG_ERR, "Invalid address/ Address not supported: %s", SERVER_IP);
        close(sockfd);
        sockfd = -1;
        return 1; // Indicate failure
    }

    if (connect(sockfd, (struct sockaddr *)&serv_addr, sizeof(serv_addr)) < 0) {
        syslog(LOG_ERR, "Error connecting to server: %s", strerror(errno));
        close(sockfd);
        sockfd = -1;
        return 1; // Indicate failure
    }

    syslog(LOG_INFO, "Connected to server");
    return 0; // Indicate success
}

// Function to disconnect from the server
void disconnect_from_server() {
    if (sockfd!= -1) {
        close(sockfd);
        sockfd = -1;
        syslog(LOG_INFO, "Disconnected from server");
    }
}

int main() {
    // Initialize syslog
    openlog("motion_detector", LOG_PID | LOG_CONS, LOG_USER);

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio()!= 0) {
        syslog(LOG_ERR, "GPIO initialization failed. Exiting.");
        closelog();
        return 1;
    }

    // Connect to the server
    if (connect_to_server()!= 0) {
        syslog(LOG_ERR, "Failed to connect to server. Exiting.");
        closelog();
        return 1;
    }

    // Main loop
    char buffer[1024];
    while (1) {
        // Receive message from the server
        if (receive_message(buffer, sizeof(buffer))!= 0) {
            // Attempt to reconnect if the server disconnected
            disconnect_from_server();
            if (connect_to_server()!= 0) {
                syslog(LOG_ERR, "Failed to reconnect to server. Exiting.");
                break; // Exit the loop if reconnect fails
            }
        }

        // Check if the server sent "ACTIVATE_RELAY"
        if (strstr(buffer, "ACTIVATE_RELAY")!= NULL) {
            printf("Received command to activate relay\n");
            activate_relay();
            gpioDelay(RELAY_ACTIVATION_TIME * 1000000); // Delay for relay activation time
            deactivate_relay();

            // Send a confirmation message back to the server
            if (send_message("RELAY_ACTIVATED")!= 0) {
                // Attempt to reconnect if the server disconnected
                disconnect_from_server();
                if (connect_to_server()!= 0) {
                    syslog(LOG_ERR, "Failed to reconnect to server after relay activation. Continuing without it.");
                }
            }
        }

        // Small delay to prevent busy-waiting
        gpioDelay(100000); // 100ms
    }

    // Cleanup before exiting
    disconnect_from_server();
    deactivate_relay();
    gpioTerminate();
    closelog();

    return 0;
}

