// Global variables
static volatile int last_interrupt_time = 0;

// Function to format timestamp and log to file (simulates a remote service)
void log_motion_event() {
    time_t rawtime;
    struct tm *info;
    char buffer[80];

    time(&rawtime);
    info = gmtime(&rawtime); // Use gmtime for UTC/Zulu time

    strftime(buffer, 80, "%Y-%m-%dT%H:%M:%SZ", info);

    FILE *fp = fopen("motion.log", "a");
    if (fp != NULL) {
        fprintf(fp, "%s\n", buffer);
        fclose(fp);
        printf("Motion event logged: %s\n", buffer);
    } else {
        perror("Error opening motion.log");
    }
}

// Interrupt handler for PIR sensor
void motion_detected_callback(int gpio, int level, uint32_t tick) {
    int current_time;
    struct timespec spec;

    clock_gettime(CLOCK_REALTIME, &spec);
    current_time = spec.tv_sec * 1000 + spec.tv_nsec / 1000000; // Get current time in milliseconds

    // Debounce the signal
    if (current_time - last_interrupt_time > DEBOUNCE_TIME) {
        printf("Motion detected!\n");

        // Trigger the buzzer for 1 second
        gpioWrite(BUZZER_PIN, 1); // Turn on buzzer
        gpioDelay(1000);          // Wait for 1 second
        gpioWrite(BUZZER_PIN, 0); // Turn off buzzer

        // Log the motion event
        log_motion_event();

        last_interrupt_time = current_time;
    }
}

