#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>
#include <string.h>
#include <signal.h>
#include <unistd.h>

// Define GPIO pins
#define PIR_PIN 17
#define BUZZER_PIN 18

// Define constants
#define DEBOUNCE_DELAY 200  // Debounce delay in milliseconds
#define BUZZER_DURATION 1000 // Buzzer duration in milliseconds
#define LOG_FILE "motion.log"

// Global variables
FILE *log_file = NULL;
volatile sig_atomic_t program_running = 1;

// Function prototypes
int initialize_gpio(void);
void motion_detected_callback(int gpio, int level, uint32_t tick, void *userdata);
void activate_buzzer(int duration_ms);
void log_motion_event(void);
void signal_handler(int signal);
void cleanup(void);

// Function to initialize GPIO pins
int initialize_gpio(void) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }

    gpioSetMode(PIR_PIN, PI_INPUT);
    gpioSetPullUpDown(PIR_PIN, PI_PUD_DOWN); // Use pull-down resistor
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioWrite(BUZZER_PIN, 0); // Ensure buzzer is off initially

    return 0;
}

// Callback function for motion detection
void motion_detected_callback(int gpio, int level, uint32_t tick, void *userdata) {
    static uint32_t last_tick = 0;
    uint32_t current_tick = gpioTick();

    if (current_tick - last_tick > DEBOUNCE_DELAY * 1000) { // Convert milliseconds to microseconds
        activate_buzzer(BUZZER_DURATION);
        log_motion_event();
        last_tick = current_tick;
    }
}

// Function to activate the buzzer
void activate_buzzer(int duration_ms) {
    gpioWrite(BUZZER_PIN, 1); // Turn buzzer on
    gpioDelay(duration_ms * 1000); // Delay for specified duration
    gpioWrite(BUZZER_PIN, 0); // Turn buzzer off
}

// Function to log the motion event to a file
void log_motion_event(void) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[20];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%SZ", timeinfo);

    if (log_file!= NULL) {
        fprintf(log_file, "%s\n", timestamp);
        fflush(log_file); // Ensure data is written to disk immediately
    } else {
        fprintf(stderr, "Error: Log file is not open.\n");
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Ctrl+C pressed. Exiting gracefully...\n");
        program_running = 0;
    }
}

// Cleanup function to release resources
void cleanup(void) {
    printf("Cleaning up...\n");
    gpioWrite(BUZZER_PIN, 0); // Turn off buzzer
    gpioTerminate(); // Release pigpio resources

    if (log_file!= NULL) {
        fclose(log_file);
    }
}

int main(void) {
    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize GPIO
    if (initialize_gpio()!= 0) {
        return 1;
    }

    // Open the log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", LOG_FILE);
        gpioTerminate(); // Release pigpio resources before exiting
        return 1;
    }

    // Set up interrupt on PIR pin with debouncing
    if (gpioSetAlertFuncEx(PIR_PIN, motion_detected_callback, NULL)!= 0) {
        fprintf(stderr, "Error setting up interrupt on PIR pin.\n");
        cleanup();
        return 1;
    }

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    // Main loop
    while (program_running) {
        sleep(1); // Reduce CPU usage
    }

    // Cleanup and exit
    cleanup();
    return 0;
}

