// Function to initialize I2C communication
int initialize_i2c(int bus, int address) {
    int fd = open("/dev/i2c-" + bus, O_RDWR);
    if (fd < 0) {
        perror("Error opening I2C bus");
        return -1;
    }

    if (ioctl(fd, I2C_SLAVE, address) < 0) {
        perror("Error setting I2C slave address");
        close(fd);
        return -1;
    }

    return fd;
}

// Function to read data from the BH1750 sensor
float read_bh1750(int fd, int mode) {
    uint8_t config_data[2];
    config_data[0] = 0x00; // No special configuration needed
    config_data[1] = mode;  // Mode: High Resolution Mode
    if (write(fd, config_data, 2)!= 2) {
        perror("Error writing to I2C device");
        return -1.0;
    }

    gpioDelay(200); // Wait for measurement (adjust as needed)

    uint8_t raw_data[2];
    if (read(fd, raw_data, 2)!= 2) {
        perror("Error reading from I2C device");
        return -1.0;
    }

    // Combine the two bytes into a single 16-bit value
    uint16_t raw_value = (raw_data[0] << 8) | raw_data[1];

    // Convert to lux
    float lux = (float)raw_value / 1.2;

    return lux;
}

